{
  "name": "Kinetic Prototype",
  "description": "A physiotherapy clinic shared history platform based on an incentive-driven credit system."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Status {
  RESOLVED = 'Resolved',
  ONGOING = 'Ongoing',
  PLATEAUED = 'Plateaued'
}

export enum TreatmentType {
  MANUAL_THERAPY = 'Manual Therapy',
  DRY_NEEDLING = 'Dry Needling',
  EXERCISE_REHAB = 'Exercise Rehab',
  ULTRASOUND = 'Ultrasound',
  TAPING = 'Taping',
  MANIPULATION = 'Manipulation'
}

export interface Patient {
  id: string;
  name: string; // In real app, this might be obscured until consent
  dob: string;
  lastVisit: string;
  historyAvailable: boolean;
}

export interface HistoryEntry {
  id: string;
  patientId: string;
  condition: string; // e.g., "ACL Tear"
  timelineStart: string;
  timelineEnd?: string;
  status: Status;
  successfulTreatments: TreatmentType[];
  unsuccessfulTreatments: TreatmentType[];
  contraindications: string[]; // Structured tags, not free text
  createdAt: string;
  // Metadata
  sourceClinicHash: string; // Anonymized
}

export interface ClinicState {
  name: string;
  credits: number;
  optedIn: boolean;
  unlockedPatients: string[]; // List of patient IDs where history is unlocked
  contributionCount: number;
}

import React from 'react';
import { LayoutDashboard, Users, FilePlus, Settings, Activity, ShieldCheck, Share2 } from 'lucide-react';

interface LayoutProps {
  children: React.ReactNode;
  activeTab: string;
  onTabChange: (tab: string) => void;
  credits: number;
}

export const Layout: React.FC<LayoutProps> = ({ children, activeTab, onTabChange, credits }) => {
  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutDashboard },
    { id: 'intake', label: 'Patient Intake', icon: Users },
    { id: 'contribute', label: 'Contribute History', icon: FilePlus },
    { id: 'referrals', label: 'Referrals', icon: Share2 },
    { id: 'settings', label: 'Settings', icon: Settings },
  ];

  return (
    <div className="flex h-screen bg-slate-50 text-slate-900 overflow-hidden font-sans">
      {/* Sidebar */}
      <aside className="w-64 bg-slate-900 text-white flex-shrink-0 flex flex-col shadow-xl z-20">
        <div className="p-6 flex items-center space-x-2 border-b border-slate-800">
          <div className="bg-kinetic-500 p-2 rounded-lg">
            <Activity className="w-6 h-6 text-white" />
          </div>
          <span className="text-xl font-bold tracking-tight">Kinetic</span>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => onTabChange(item.id)}
              className={`w-full flex items-center space-x-3 px-4 py-3 rounded-lg transition-all duration-200 ${
                activeTab === item.id
                  ? 'bg-kinetic-600 text-white shadow-lg'
                  : 'text-slate-400 hover:bg-slate-800 hover:text-white'
              }`}
            >
              <item.icon className="w-5 h-5" />
              <span className="font-medium">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="p-4 bg-slate-800 m-4 rounded-xl border border-slate-700">
          <div className="flex items-center space-x-2 mb-2 text-slate-300 text-xs uppercase font-semibold tracking-wider">
            <ShieldCheck className="w-4 h-4 text-kinetic-500" />
            <span>Clinic Status</span>
          </div>
          <div className="text-white font-medium">Opted In</div>
          <div className="text-xs text-slate-400 mt-1">Network Active</div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 overflow-hidden">
        {/* Sticky Header */}
        <header className="h-16 bg-white border-b border-slate-200 flex items-center justify-between px-8 shadow-sm z-10 sticky top-0">
          <h1 className="text-xl font-semibold text-slate-800 capitalize">
            {navItems.find(n => n.id === activeTab)?.label}
          </h1>

          <div className="flex items-center space-x-6">
            <div className="flex items-center bg-slate-100 rounded-full px-4 py-1.5 border border-slate-200">
              <span className="text-sm text-slate-500 mr-2 font-medium">History Credits</span>
              <div className={`text-lg font-bold ${credits > 0 ? 'text-kinetic-600' : 'text-red-500'}`}>
                {credits}
              </div>
            </div>
            <div className="h-8 w-8 rounded-full bg-slate-200 flex items-center justify-center text-slate-600 font-bold border border-slate-300">
              KC
            </div>
          </div>
        </header>

        {/* Scrollable Content */}
        <div className="flex-1 overflow-y-auto p-8">
          <div className="max-w-5xl mx-auto">
            {children}
          </div>
        </div>
      </main>
    </div>
  );
};

import React, { useState } from 'react';
import { Search, Lock, Unlock, AlertTriangle, FileText, Calendar, CheckCircle, Activity, User } from 'lucide-react';
import { Patient, HistoryEntry } from '../types';

interface PatientSearchProps {
  patients: Patient[];
  histories: HistoryEntry[];
  unlockedPatients: string[];
  credits: number;
  onUnlock: (patientId: string) => void;
}

export const PatientSearch: React.FC<PatientSearchProps> = ({ 
  patients, 
  histories, 
  unlockedPatients, 
  credits, 
  onUnlock 
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const patientHistory = selectedPatient 
    ? histories.find(h => h.patientId === selectedPatient.id) 
    : null;

  const isUnlocked = selectedPatient ? unlockedPatients.includes(selectedPatient.id) : false;

  const handleUnlock = () => {
    if (selectedPatient && credits > 0) {
      onUnlock(selectedPatient.id);
    }
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-full">
      {/* Search Column */}
      <div className="lg:col-span-1 flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50">
          <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 block">Find Patient</label>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input
              type="text"
              className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-kinetic-500 focus:border-kinetic-500 outline-none"
              placeholder="Search name or ID..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-2 space-y-2">
          {filteredPatients.map(patient => (
            <div
              key={patient.id}
              onClick={() => setSelectedPatient(patient)}
              className={`p-3 rounded-lg cursor-pointer transition-colors border ${
                selectedPatient?.id === patient.id
                  ? 'bg-kinetic-50 border-kinetic-200'
                  : 'bg-white border-transparent hover:bg-slate-50 hover:border-slate-200'
              }`}
            >
              <div className="flex items-center justify-between">
                <div>
                  <h4 className="font-semibold text-slate-900">{patient.name}</h4>
                  <p className="text-xs text-slate-500">ID: {patient.id} • DOB: {patient.dob}</p>
                </div>
                {patient.historyAvailable && (
                  <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-indigo-100 text-indigo-800">
                    History
                  </span>
                )}
              </div>
            </div>
          ))}
          {filteredPatients.length === 0 && (
            <div className="text-center py-8 text-slate-400 text-sm">No patients found.</div>
          )}
        </div>
      </div>

      {/* Detail Column */}
      <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 h-full overflow-hidden flex flex-col">
        {!selectedPatient ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <User className="w-16 h-16 mb-4 opacity-20" />
            <p>Select a patient to view details</p>
          </div>
        ) : (
          <>
            {/* Header */}
            <div className="p-6 border-b border-slate-100 flex justify-between items-start bg-slate-50">
              <div>
                <h2 className="text-2xl font-bold text-slate-900">{selectedPatient.name}</h2>
                <div className="flex items-center space-x-4 mt-2 text-sm text-slate-600">
                  <span className="flex items-center"><Calendar className="w-4 h-4 mr-1" /> DOB: {selectedPatient.dob}</span>
                  <span className="flex items-center"><Activity className="w-4 h-4 mr-1" /> Last Visit: {selectedPatient.lastVisit}</span>
                </div>
              </div>
              <div className={`px-3 py-1 rounded-full text-sm font-medium flex items-center ${
                selectedPatient.historyAvailable 
                  ? 'bg-emerald-100 text-emerald-800' 
                  : 'bg-slate-100 text-slate-600'
              }`}>
                {selectedPatient.historyAvailable ? (
                  <><CheckCircle className="w-4 h-4 mr-1.5" /> History Available</>
                ) : (
                  'No Prior History'
                )}
              </div>
            </div>

            {/* Content Area */}
            <div className="flex-1 overflow-y-auto p-6 relative">
              {!selectedPatient.historyAvailable ? (
                 <div className="text-center py-12 bg-slate-50 rounded-lg border border-dashed border-slate-300">
                   <p className="text-slate-500">No external history found for this patient.</p>
                 </div>
              ) : isUnlocked ? (
                /* Unlocked View */
                patientHistory ? (
                  <div className="space-y-6 animate-fade-in">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                        <label className="text-xs font-bold text-slate-400 uppercase mb-1 block">Primary Condition</label>
                        <p className="text-lg font-semibold text-slate-900">{patientHistory.condition}</p>
                        <div className="mt-2 flex space-x-2">
                           <span className={`px-2 py-0.5 rounded text-xs font-bold uppercase ${
                             patientHistory.status === 'Resolved' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                           }`}>{patientHistory.status}</span>
                        </div>
                      </div>
                      <div className="bg-slate-50 p-4 rounded-lg border border-slate-200">
                        <label className="text-xs font-bold text-slate-400 uppercase mb-1 block">Timeline</label>
                        <p className="text-sm text-slate-800">{patientHistory.timelineStart} — {patientHistory.timelineEnd || 'Present'}</p>
                        <label className="text-xs font-bold text-slate-400 uppercase mt-4 mb-1 block">Source</label>
                        <p className="text-xs text-slate-500 font-mono">Anonymized Clinic ({patientHistory.sourceClinicHash.substring(0,8)})</p>
                      </div>
                    </div>

                    <div>
                       <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wide border-b border-slate-200 pb-2 mb-4">Treatment Efficacy</h3>
                       <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                         <div>
                            <span className="text-xs font-semibold text-emerald-600 block mb-2">Effective Interventions</span>
                            <div className="flex flex-wrap gap-2">
                              {patientHistory.successfulTreatments.map(t => (
                                <span key={t} className="px-3 py-1 bg-white border border-emerald-200 text-emerald-700 rounded-md text-sm shadow-sm">
                                  {t}
                                </span>
                              ))}
                            </div>
                         </div>
                         <div>
                            <span className="text-xs font-semibold text-rose-600 block mb-2">Ineffective Interventions</span>
                            <div className="flex flex-wrap gap-2">
                              {patientHistory.unsuccessfulTreatments.map(t => (
                                <span key={t} className="px-3 py-1 bg-white border border-rose-200 text-rose-700 rounded-md text-sm shadow-sm">
                                  {t}
                                </span>
                              ))}
                            </div>
                         </div>
                       </div>
                    </div>

                    <div>
                      <h3 className="text-sm font-bold text-slate-900 uppercase tracking-wide border-b border-slate-200 pb-2 mb-4">Safety & Contraindications</h3>
                      <div className="bg-rose-50 border border-rose-100 rounded-lg p-4">
                        <div className="flex flex-wrap gap-2">
                          {patientHistory.contraindications.map(c => (
                            <span key={c} className="flex items-center px-3 py-1 bg-white text-rose-700 border border-rose-200 rounded-md text-sm font-medium">
                              <AlertTriangle className="w-3 h-3 mr-1.5" />
                              {c}
                            </span>
                          ))}
                          {patientHistory.contraindications.length === 0 && <span className="text-sm text-rose-400 italic">None recorded</span>}
                        </div>
                      </div>
                    </div>

                    <div className="pt-8 border-t border-slate-100 flex justify-between items-center">
                      <p className="text-xs text-slate-400">
                        Access ID: {Math.random().toString(36).substring(7).toUpperCase()} • Viewed {new Date().toLocaleDateString()}
                      </p>
                      <button className="text-kinetic-600 text-sm font-medium hover:underline flex items-center">
                        <FileText className="w-4 h-4 mr-1" />
                        Download Report
                      </button>
                    </div>
                  </div>
                ) : <div className="text-red-500">Error loading history data.</div>
              ) : (
                /* Locked View */
                <div className="absolute inset-0 bg-slate-50 flex flex-col items-center justify-center p-8 z-10">
                   <div className="bg-white p-8 rounded-2xl shadow-xl border border-slate-200 max-w-md w-full text-center">
                      <div className="mx-auto w-16 h-16 bg-slate-100 rounded-full flex items-center justify-center mb-6">
                        <Lock className="w-8 h-8 text-slate-400" />
                      </div>
                      <h3 className="text-xl font-bold text-slate-900 mb-2">Structured History Available</h3>
                      <p className="text-slate-500 mb-8">
                        This patient has verified clinical history from the Kinetic network. Unlock to view outcomes, contraindications, and timelines.
                      </p>

                      <div className="flex items-center justify-center space-x-2 text-sm text-slate-500 mb-6 bg-slate-50 py-2 rounded-lg border border-slate-100">
                        <span>Cost:</span>
                        <span className="font-bold text-slate-900">1 Credit</span>
                        <span className="text-slate-300">|</span>
                        <span>Your Balance:</span>
                        <span className={`font-bold ${credits > 0 ? 'text-emerald-600' : 'text-red-500'}`}>{credits}</span>
                      </div>

                      <button
                        onClick={handleUnlock}
                        disabled={credits <= 0}
                        className={`w-full flex items-center justify-center px-6 py-3 rounded-xl font-bold text-white transition-all transform active:scale-95 ${
                          credits > 0 
                            ? 'bg-kinetic-600 hover:bg-kinetic-700 shadow-lg shadow-kinetic-200' 
                            : 'bg-slate-300 cursor-not-allowed'
                        }`}
                      >
                        {credits > 0 ? (
                          <>
                            <Unlock className="w-5 h-5 mr-2" />
                            Unlock History
                          </>
                        ) : (
                          <>
                            <Lock className="w-5 h-5 mr-2" />
                            Insufficient Credits
                          </>
                        )}
                      </button>

                      {credits <= 0 && (
                        <p className="mt-4 text-xs text-rose-500 font-medium">
                          Contribute a patient history to earn more credits.
                        </p>
                      )}
                   </div>

                   {/* Blurred Preview Background */}
                   <div className="absolute top-0 left-0 w-full h-full -z-10 opacity-30 filter blur-sm pointer-events-none p-6 space-y-4">
                      <div className="h-32 bg-slate-300 rounded-lg w-full"></div>
                      <div className="h-16 bg-slate-300 rounded-lg w-2/3"></div>
                      <div className="h-48 bg-slate-300 rounded-lg w-full"></div>
                   </div>
                </div>
              )}
            </div>
          </>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Check, Info, Plus, X } from 'lucide-react';
import { Status, TreatmentType } from '../types';
import { TREATMENTS_LIST, CONTRAINDICATIONS_LIST } from '../constants';

interface ContributionFormProps {
  onSubmit: (data: any) => void;
}

export const ContributionForm: React.FC<ContributionFormProps> = ({ onSubmit }) => {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [formData, setFormData] = useState({
    patientId: '',
    condition: '',
    status: Status.ONGOING,
    start: '',
    end: '',
    successful: [] as string[],
    unsuccessful: [] as string[],
    contraindications: [] as string[]
  });

  const toggleSelection = (field: 'successful' | 'unsuccessful' | 'contraindications', value: string) => {
    setFormData(prev => {
      const current = prev[field];
      if (current.includes(value)) {
        return { ...prev, [field]: current.filter(item => item !== value) };
      } else {
        return { ...prev, [field]: [...current, value] };
      }
    });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    // Simulate API delay
    setTimeout(() => {
      onSubmit(formData);
      setIsSubmitting(false);
    }, 1500);
  };

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8">
        <h2 className="text-2xl font-bold text-slate-900">Contribute Patient History</h2>
        <p className="text-slate-500 mt-2">
          Earn 1 Kinetic Point by sharing structured outcome data. 
          <span className="font-semibold text-slate-700 ml-1">No free text or subjective notes allowed.</span>
        </p>
      </div>

      <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        {/* Progress Bar */}
        <div className="h-2 bg-slate-100 flex">
          <div className={`h-full bg-kinetic-500 transition-all duration-500 ${step === 1 ? 'w-1/2' : 'w-full'}`}></div>
        </div>

        <div className="p-8 space-y-8">
          {step === 1 && (
            <div className="space-y-6 animate-fade-in">
              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Patient ID / Reference</label>
                  <input 
                    required
                    type="text" 
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-kinetic-500 outline-none"
                    placeholder="e.g. P-10293"
                    value={formData.patientId}
                    onChange={e => setFormData({...formData, patientId: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Primary Condition</label>
                  <input 
                    required
                    type="text" 
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-kinetic-500 outline-none"
                    placeholder="e.g. Achilles Tendinopathy"
                    value={formData.condition}
                    onChange={e => setFormData({...formData, condition: e.target.value})}
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-3">Outcome Status</label>
                <div className="flex space-x-4">
                  {Object.values(Status).map((s) => (
                    <button
                      key={s}
                      type="button"
                      onClick={() => setFormData({...formData, status: s})}
                      className={`flex-1 py-3 px-4 rounded-lg border text-sm font-semibold transition-all ${
                        formData.status === s
                          ? 'bg-kinetic-50 border-kinetic-500 text-kinetic-700 ring-1 ring-kinetic-500'
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Treatment Start</label>
                  <input 
                    type="date" 
                    required
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-kinetic-500 outline-none"
                    value={formData.start}
                    onChange={e => setFormData({...formData, start: e.target.value})}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Treatment End (Optional)</label>
                  <input 
                    type="date" 
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-kinetic-500 outline-none"
                    value={formData.end}
                    onChange={e => setFormData({...formData, end: e.target.value})}
                  />
                </div>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-8 animate-fade-in">
              {/* Successful */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2 flex items-center">
                  <Check className="w-4 h-4 text-emerald-500 mr-2" />
                  What Worked? (Successful Interventions)
                </label>
                <div className="flex flex-wrap gap-2">
                  {TREATMENTS_LIST.map(t => (
                    <button
                      key={t}
                      type="button"
                      onClick={() => toggleSelection('successful', t)}
                      className={`px-3 py-1.5 rounded-full text-sm font-medium border transition-colors ${
                        formData.successful.includes(t)
                          ? 'bg-emerald-100 border-emerald-500 text-emerald-800'
                          : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                      }`}
                    >
                      {t}
                    </button>
                  ))}
                </div>
              </div>

              {/* Unsuccessful */}
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2 flex items-center">
                  <X className="w-4 h-4 text-rose-500 mr-2" />
                  What Didn't Work? (Unsuccessful Interventions)
                </label>
                <div className="flex flex-wrap gap-2">
                  {TREATMENTS_LIST.map(t => (
                    <button
                      key={t}
                      type="button"
                      onClick={() => toggleSelection('unsuccessful', t)}
                      className={`px-3 py-1.5 rounded-full text-sm font-medium border transition-colors ${
                        formData.unsuccessful.includes(t)
                          ? 'bg-rose-100 border-rose-500 text-rose-800'
                          : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                      }`}
                    >
                      {t}
                    </button>
                  ))}
                </div>
              </div>

              {/* Contraindications */}
              <div className="p-4 bg-amber-50 rounded-lg border border-amber-100">
                <label className="block text-sm font-bold text-amber-800 mb-2 flex items-center">
                  <Info className="w-4 h-4 mr-2" />
                  Safety & Contraindications
                </label>
                <p className="text-xs text-amber-700 mb-3">
                   Select any specific red flags or treatments that should be avoided for this patient.
                </p>
                <div className="flex flex-wrap gap-2">
                  {CONTRAINDICATIONS_LIST.map(c => (
                    <button
                      key={c}
                      type="button"
                      onClick={() => toggleSelection('contraindications', c)}
                      className={`px-3 py-1.5 rounded text-xs font-bold uppercase tracking-wide border transition-colors ${
                        formData.contraindications.includes(c)
                          ? 'bg-amber-600 border-amber-700 text-white shadow-sm'
                          : 'bg-white border-amber-200 text-amber-800 hover:bg-amber-100'
                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>

        {/* Footer Actions */}
        <div className="px-8 py-4 bg-slate-50 border-t border-slate-200 flex justify-between items-center">
          {step === 2 ? (
            <button
              type="button"
              onClick={() => setStep(1)}
              className="text-slate-600 font-medium hover:text-slate-900"
            >
              Back
            </button>
          ) : (
            <div></div> /* Spacer */
          )}

          {step === 1 ? (
            <button
              type="button"
              onClick={() => setStep(2)}
              className="bg-slate-900 text-white px-6 py-2 rounded-lg font-semibold hover:bg-slate-800 transition-colors"
            >
              Next Step
            </button>
          ) : (
            <button
              type="submit"
              disabled={isSubmitting}
              className={`flex items-center space-x-2 px-6 py-2 rounded-lg font-semibold text-white transition-all ${
                isSubmitting 
                  ? 'bg-kinetic-400 cursor-wait' 
                  : 'bg-kinetic-600 hover:bg-kinetic-700 shadow-lg shadow-kinetic-200/50'
              }`}
            >
              {isSubmitting ? (
                'Submitting...'
              ) : (
                <>
                  <Plus className="w-5 h-5" />
                  <span>Submit & Earn Credit</span>
                </>
              )}
            </button>
          )}
        </div>
      </form>
    </div>
  );
};

