import React, { useState, useEffect, useCallback } from 'react';
import { Check, Info, Plus, X, Save, ArrowRight, RefreshCcw, FileText, AlertCircle, Loader2 } from 'lucide-react';
import { Status, TreatmentType } from '../types';
import { TREATMENTS_LIST, CONTRAINDICATIONS_LIST } from '../constants';

interface ContributionFormProps {
  onSubmit: (data: any) => void;
}

const STORAGE_KEY = 'kinetic_contribution_draft';

export const ContributionForm: React.FC<ContributionFormProps> = ({ onSubmit }) => {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [error, setError] = useState<string | null>(null);

  // Initial State
  const initialFormState = {
    patientId: '',
    condition: '',
    status: Status.ONGOING,
    start: '',
    end: '',
    successful: [] as string[],
    unsuccessful: [] as string[],
    contraindications: [] as string[]
  };

  const [formData, setFormData] = useState(initialFormState);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load draft from LocalStorage on mount
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        setFormData(JSON.parse(savedData));
        setLastSaved(new Date());
      } catch (e) {
        console.error("Failed to parse draft", e);
      }
    }
    setIsLoaded(true);
  }, []);

  // Save to LocalStorage when formData changes (Debounced)
  useEffect(() => {
    if (!isLoaded) return;

    setIsSaving(true);
    const handler = setTimeout(() => {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
      setLastSaved(new Date());
      setIsSaving(false);
    }, 1000); // 1 second debounce

    return () => clearTimeout(handler);
  }, [formData, isLoaded]);

  const handleInputChange = (field: string, value: any) => {
    setError(null); // Clear errors on edit
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const toggleSelection = (field: 'successful' | 'unsuccessful' | 'contraindications', value: string) => {
    setError(null);
    setFormData(prev => {
      const current = prev[field];
      if (current.includes(value)) {
        return { ...prev, [field]: current.filter(item => item !== value) };
      } else {
        return { ...prev, [field]: [...current, value] };
      }
    });
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSubmitting(true);
    setError(null);

    try {
      // Simulate API Network Call
      await new Promise((resolve, reject) => {
        setTimeout(() => {
          // Simulate a random error for demonstration purposes (rare)
          const isError = Math.random() > 0.95; 
          if (isError) {
             reject(new Error("Network connection timed out. Please try again."));
          } else {
             resolve(true);
          }
        }, 1500);
      });

      // Success Logic
      onSubmit(formData);
      localStorage.removeItem(STORAGE_KEY); // Clear draft
      setStep(3); // Navigate to Success Step internal to form
    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleReset = () => {
    setFormData(initialFormState);
    localStorage.removeItem(STORAGE_KEY);
    setStep(1);
    setLastSaved(null);
    setError(null);
  };

  if (step === 3) {
    return (
