           {isSaving ? (
              <div className="flex items-center text-xs font-medium text-slate-400 bg-slate-100 px-3 py-1 rounded-full transition-opacity">
                <Loader2 className="w-3 h-3 mr-1.5 animate-spin" />
                Saving...
              </div>
           ) : lastSaved ? (
              <div className="flex items-center text-xs font-medium text-slate-500 bg-slate-100 px-3 py-1 rounded-full animate-fade-in transition-opacity">
                <Save className="w-3 h-3 mr-1.5 text-slate-400" />
                Draft saved
              </div>
           ) : null}
        </div>
      </div>

      <form onSubmit={handleSubmit} className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden relative">
        {/* Progress Bar */}
        <div className="h-2 bg-slate-100 flex">
          <div className={`h-full bg-kinetic-500 transition-all duration-500 ${step === 1 ? 'w-1/2' : 'w-full'}`}></div>
        </div>

        {/* Error Banner */}
        {error && (
          <div className="bg-rose-50 border-b border-rose-100 p-4 flex items-center text-rose-800 text-sm animate-fade-in">
            <AlertCircle className="w-5 h-5 mr-3 flex-shrink-0" />
