import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { PatientSearch } from './components/PatientSearch';
import { ContributionForm } from './components/ContributionForm';
import { Referral } from './components/Referral';
import { MOCK_PATIENTS, MOCK_HISTORY } from './constants';
import { Patient, HistoryEntry, Status } from './types';
import { CheckCircle, Shield, PlayCircle, AlertTriangle, CalendarClock } from 'lucide-react';

// Simple Alert Component for notifications
const Notification = ({ message, onClose }: { message: string; onClose: () => void }) => (
  <div className="fixed bottom-6 right-6 bg-slate-900 text-white px-6 py-4 rounded-xl shadow-2xl flex items-center animate-bounce-in z-50">
    <CheckCircle className="w-6 h-6 text-emerald-400 mr-3" />
    <div>
      <h4 className="font-bold text-sm">Success</h4>
      <p className="text-sm text-slate-300">{message}</p>
    </div>
    <button onClick={onClose} className="ml-6 text-slate-400 hover:text-white">✕</button>
  </div>
);

const App: React.FC = () => {
  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [credits, setCredits] = useState(0); // Start with 0 until opt-in
  const [pointsExpiry, setPointsExpiry] = useState<Date | null>(null);
  const [unlockedPatients, setUnlockedPatients] = useState<string[]>([]);
  const [contributionCount, setContributionCount] = useState(12);
  const [localHistory, setLocalHistory] = useState<HistoryEntry[]>(MOCK_HISTORY);
  const [localPatients, setLocalPatients] = useState<Patient[]>(MOCK_PATIENTS);
  const [notification, setNotification] = useState<string | null>(null);

  // Persistent SOAP Drafts
  const [soapDrafts, setSoapDrafts] = useState<Record<string, { s: string; o: string; a: string; p: string }>>({});

  // Phase 1 Logic
  const [optedIn, setOptedIn] = useState(false);
  const isEligible = true; // Hardcoded for demo: "Riversdale Physio" is inner-city/high-turnover

  // Clear notification when changing tabs to avoid stale messages
  useEffect(() => {
    setNotification(null);
  }, [activeTab]);

  // Actions
  const handleUnlockPatient = (patientId: string) => {
    if (!optedIn) {
      setNotification('Must Opt-In to network to unlock history.');
      setTimeout(() => setNotification(null), 3000);
      return;
    }

    if (unlockedPatients.includes(patientId)) {
      // Already unlocked, do nothing or notify
      return;
    }

    if (pointsExpiry && new Date() > pointsExpiry) {
      setNotification('Points have expired. Contribute to earn fresh points.');
      setTimeout(() => setNotification(null), 3000);
      return;
    }

    if (credits > 0) {
      setCredits(prev => prev - 1);
      setUnlockedPatients(prev => [...prev, patientId]);
      setNotification(`Unlocked history. Balance: ${credits - 1}`);
      setTimeout(() => setNotification(null), 3000);
    }
  };

  const handleUploadReport = (patientId: string, fileName: string) => {
    // Find history entry for this patient
    const historyIndex = localHistory.findIndex(h => h.patientId === patientId);

    if (historyIndex >= 0) {
      const updatedHistory = [...localHistory];
      updatedHistory[historyIndex] = {
        ...updatedHistory[historyIndex],
        reportFile: fileName
      };
      setLocalHistory(updatedHistory);
      setNotification('SOAP Report uploaded successfully.');
      setTimeout(() => setNotification(null), 3000);
    } else {
      setNotification('Error: No history found for this patient.');
      setTimeout(() => setNotification(null), 3000);
    }
  };

  const handleOptIn = () => {
    setOptedIn(true);
    setCredits(prev => prev + 5);
    // Set mock expiry date (30 days from now)
    const expiry = new Date();
    expiry.setDate(expiry.getDate() + 30);
    setPointsExpiry(expiry);

    setNotification('Network Opt-In Successful. 5 Points Granted.');
    setTimeout(() => setNotification(null), 4000);
  };

  const handleOptOut = () => {
    setOptedIn(false);
    // Logic: Freezing access? For now, we'll just set state to false
    // which effectively disables unlock capabilities in the UI checks.
    setNotification('You have opted out of the Kinetic Network.');
    setTimeout(() => setNotification(null), 3000);
  };

  const handleContribution = (data: any) => {
    if (!optedIn) {
      setNotification('Please Opt-In to contribute.');
      setTimeout(() => setNotification(null), 3000);
      return;
    }

    setCredits(prev => prev + 1);
    setContributionCount(prev => prev + 1);

    // Extend expiry if contributing? Let's say yes for demo
    const newExpiry = new Date();
    newExpiry.setDate(newExpiry.getDate() + 30);
    setPointsExpiry(newExpiry);

    // Optimistically add to local data so we can see it
    const newHistory: HistoryEntry = {
      id: `H-${Math.random().toString(36).substr(2, 9)}`,
      patientId: data.patientId,
      condition: data.condition,
      timelineStart: data.start,
      timelineEnd: data.end,
      status: data.status,
      successfulTreatments: data.successful,
      unsuccessfulTreatments: data.unsuccessful,
      contraindications: data.contraindications,
      createdAt: new Date().toISOString(),
      sourceClinicHash: 'RIVERSDALE_PHYSIO'
    };

    setLocalHistory(prev => [...prev, newHistory]);

    // Check if patient exists, if not add them
    const existingPatientIndex = localPatients.findIndex(p => p.id === data.patientId);

    if (existingPatientIndex >= 0) {
      // Update existing patient
      const updatedPatients = [...localPatients];
      updatedPatients[existingPatientIndex] = {
        ...updatedPatients[existingPatientIndex],
        historyAvailable: true
      };
      setLocalPatients(updatedPatients);
    } else {
      // Add new patient
      const newPatient: Patient = {
        id: data.patientId,
        name: `Patient ${data.patientId}`, // Placeholder name
        dob: 'Unknown',
        lastVisit: new Date().toISOString().split('T')[0],
        historyAvailable: true
      };
      setLocalPatients(prev => [...prev, newPatient]);
    }

    setNotification('Contribution verified. +1 Point earned.');
    setTimeout(() => {
      setNotification(null); 
    }, 2000);
  };

  const handleSaveSoapDraft = (patientId: string, data: { s: string; o: string; a: string; p: string }) => {
    setSoapDrafts(prev => ({
      ...prev,
      [patientId]: data
    }));
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} credits={credits}>
      {activeTab === 'dashboard' && (
        <Dashboard 
          credits={credits} 
          unlockedPatients={unlockedPatients}
          patients={localPatients}
          histories={localHistory}
          onNavigate={setActiveTab}
          onUnlock={handleUnlockPatient}
          isOptedIn={optedIn}
          pointsExpiry={pointsExpiry}
        />
      )}

      {activeTab === 'intake' && (
        <PatientSearch 
          patients={localPatients}
          histories={localHistory}
          unlockedPatients={unlockedPatients}
          credits={credits}
          onUnlock={handleUnlockPatient}
          onUploadReport={handleUploadReport}
          soapDrafts={soapDrafts}
          onSaveSoap={handleSaveSoapDraft}
          isOptedIn={optedIn}
          pointsExpiry={pointsExpiry}
        />
      )}

      {activeTab === 'contribute' && (
        <ContributionForm 
          onSubmit={handleContribution} 
          onReturn={() => setActiveTab('intake')}
        />
      )}

      {activeTab === 'referrals' && (
        <Referral />
      )}

      {activeTab === 'settings' && (
        <div className="max-w-2xl mx-auto bg-white p-8 rounded-xl shadow-sm border border-slate-200 animate-fade-in">
           <h2 className="text-2xl font-bold mb-6 text-slate-900">Settings</h2>

           <div className="space-y-8">
              {/* Phase 1 Opt-In Section */}
              <div className="p-6 bg-slate-50 rounded-xl border border-slate-200 relative overflow-hidden">
                <div className="flex items-start justify-between">
                  <div>
                    <h3 className="text-lg font-bold text-slate-900 flex items-center">
                      <Shield className={`w-5 h-5 mr-2 ${optedIn ? 'text-emerald-500' : 'text-slate-400'}`} />
                      Kinetic Network Status
                    </h3>
                    <p className="text-sm text-slate-500 mt-1 max-w-sm">
                      Participate in the shared history network. Contributing data earns points for future access.
                    </p>
                  </div>
                  <div className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide ${
                    optedIn ? 'bg-emerald-100 text-emerald-700' : 'bg-slate-200 text-slate-600'
                  }`}>
                    {optedIn ? 'Active Member' : 'Not Enrolled'}
                  </div>
                </div>

                {!optedIn && isEligible && (
                  <div className="mt-6 pt-6 border-t border-slate-200">
                    <div className="flex items-center space-x-2 text-indigo-600 font-semibold mb-2">
                      <PlayCircle className="w-4 h-4" />
                      <span>Phase 1 Pilot Eligibility Confirmed</span>
                    </div>
                    <p className="text-sm text-slate-600 mb-4">
                      Your clinic (Riversdale Physio) meets the criteria for the Phase 1 Pilot. Join today to receive 5 trial points immediately.
                    </p>
                    <button 
                      onClick={handleOptIn}
                      className="bg-indigo-600 hover:bg-indigo-700 text-white px-6 py-2 rounded-lg font-semibold shadow-lg shadow-indigo-200 transition-all flex items-center"
                    >
                      Join Network & Claim 5 Points
                    </button>
                  </div>
                )}

                {optedIn && (
                   <div className="mt-6 pt-6 border-t border-slate-200">
                      <div className="flex items-center justify-between">
                         <div className="flex items-center space-x-2 text-slate-700 font-medium">
                            <CalendarClock className="w-4 h-4 text-slate-400" />
                            <span>Points Expiry: {pointsExpiry ? pointsExpiry.toLocaleDateString() : 'N/A'}</span>
                         </div>
                         <button 
                           onClick={handleOptOut}
                           className="text-sm text-red-500 hover:text-red-700 font-medium underline"
                         >
                           Opt Out of Network
                         </button>
                      </div>
                   </div>
                )}
              </div>

              {/* Other Settings */}
              <div className="flex items-center justify-between pb-6 border-b border-slate-100">
                <div>
                  <h3 className="font-semibold text-slate-900">Auto-Refill Points</h3>
                  <p className="text-sm text-slate-500">Purchase points if contribution isn't possible</p>
                </div>
                 <div className="relative inline-block w-12 h-6 transition duration-200 ease-in-out rounded-full bg-slate-200 cursor-not-allowed">
                   <span className="absolute left-1 top-1 bg-white w-4 h-4 rounded-full shadow-md"></span>
                </div>
              </div>

              <div className="flex items-center justify-between pb-6 border-b border-slate-100">
                <div>
                  <h3 className="font-semibold text-slate-900">Data Retention</h3>
                  <p className="text-sm text-slate-500">Automatically archive contributions after 7 years</p>
                </div>
                 <div className="relative inline-block w-12 h-6 transition duration-200 ease-in-out rounded-full bg-emerald-500 cursor-pointer">
                   <span className="absolute left-1 top-1 bg-white w-4 h-4 rounded-full shadow-md transform translate-x-6"></span>
                </div>
              </div>
           </div>

           <div className="mt-8 p-4 bg-slate-50 rounded-lg text-xs text-slate-500 font-mono">
             Clinic ID: KIN-ORG-882192<br/>
             Version: v0.4.4 (Beta)
           </div>
        </div>
      )}

      {notification && (
        <Notification message={notification} onClose={() => setNotification(null)} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Search, Lock, Unlock, AlertTriangle, FileText, Calendar, CheckCircle, Activity, User, Upload, Download, Eye, Copy, Check, Save, CalendarClock } from 'lucide-react';
import { Patient, HistoryEntry } from '../types';
import { DEMO_PDF_BASE64 } from '../constants';

interface PatientSearchProps {
  patients: Patient[];
  histories: HistoryEntry[];
  unlockedPatients: string[];
  credits: number;
  onUnlock: (patientId: string) => void;
  onUploadReport: (patientId: string, fileName: string) => void;
  soapDrafts: Record<string, { s: string; o: string; a: string; p: string }>;
  onSaveSoap: (patientId: string, data: { s: string; o: string; a: string; p: string }) => void;
  isOptedIn: boolean;
  pointsExpiry: Date | null;
}

export const PatientSearch: React.FC<PatientSearchProps> = ({ 
  patients, 
  histories, 
  unlockedPatients, 
  credits, 
  onUnlock,
  onUploadReport,
  soapDrafts,
  onSaveSoap,
  isOptedIn,
  pointsExpiry
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);

  // Local state for UI feedback
  const [isUploading, setIsUploading] = useState(false);
  const [copied, setCopied] = useState(false);

  // SOAP Form State
  const [soap, setSoap] = useState({ s: '', o: '', a: '', p: '' });
  const [isSavingSoap, setIsSavingSoap] = useState(false);
  const [lastSavedSoap, setLastSavedSoap] = useState<Date | null>(null);

  // Reset states or load draft when patient changes
  useEffect(() => {
    setIsUploading(false);
    setCopied(false);
    if (selectedPatient) {
      const draft = soapDrafts[selectedPatient.id] || { s: '', o: '', a: '', p: '' };
      setSoap(draft);
    } else {
      setSoap({ s: '', o: '', a: '', p: '' });
    }
    setLastSavedSoap(null);
  }, [selectedPatient, soapDrafts]);

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const patientHistory = selectedPatient 
    ? histories.find(h => h.patientId === selectedPatient.id) 
    : null;

  const isUnlocked = selectedPatient ? unlockedPatients.includes(selectedPatient.id) : false;
  const isExpired = pointsExpiry && new Date() > pointsExpiry;

  const handleUnlock = () => {
    if (selectedPatient && credits > 0 && !isExpired && isOptedIn) {
      onUnlock(selectedPatient.id);
    }
  };

  const handleFileUpload = () => {
    if (!selectedPatient) return;
    setIsUploading(true);
    // Simulate upload delay
    setTimeout(() => {
      onUploadReport(selectedPatient.id, "soap_report_final.pdf");
      setIsUploading(false);
    }, 1500);
  };

  const handleDownloadReport = () => {
    // Convert Base64 to Blob
    const byteCharacters = atob(DEMO_PDF_BASE64);
    const byteNumbers = new Array(byteCharacters.length);
    for (let i = 0; i < byteCharacters.length; i++) {
      byteNumbers[i] = byteCharacters.charCodeAt(i);
    }
    const byteArray = new Uint8Array(byteNumbers);
    const blob = new Blob([byteArray], { type: 'application/pdf' });

    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', patientHistory?.reportFile || 'soap_report.pdf');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);
  };

  const handleCopyHistory = () => {
    if (!patientHistory) return;
    const text = `
Patient History: ${selectedPatient?.name} (ID: ${selectedPatient?.id})
Condition: ${patientHistory.condition}
Status: ${patientHistory.status}
Timeline: ${patientHistory.timelineStart} - ${patientHistory.timelineEnd || 'Present'}

Effective Interventions:
${patientHistory.successfulTreatments.join(', ') || 'None listed'}

Ineffective Interventions:
${patientHistory.unsuccessfulTreatments.join(', ') || 'None listed'}

Contraindications:
${patientHistory.contraindications.join(', ') || 'None listed'}

Source: Kinetic Network (${patientHistory.sourceClinicHash.substring(0,8)})
    `.trim();

    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSaveSoap = () => {
    if (!selectedPatient) return;
    setIsSavingSoap(true);
    // Call parent handler to save draft
    onSaveSoap(selectedPatient.id, soap);
    setTimeout(() => {
      setIsSavingSoap(false);
      setLastSavedSoap(new Date());
    }, 500);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 h-full">
      {/* Search Column */}
      <div className="lg:col-span-1 flex flex-col h-full bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 border-b border-slate-100 bg-slate-50">
          <label className="text-xs font-bold text-slate-500 uppercase tracking-wide mb-2 block">Find Patient</label>
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input
              type="text"
              className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-kinetic-500 focus:border-kinetic-500 outline-none"
              placeholder="Search name or ID..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>
        <div className="flex-1 overflow-y-auto p-2 space-y-2">
          {filteredPatients.map(patient => (
            <div
              key={patient.id}
              onClick={() => setSelectedPatient(patient)}
              className={`p-3 rounded-lg cursor-pointer transition-colors border ${
                selectedPatient?.id === patient.id
                  ? 'bg-kinetic-50 border-kinetic-200'
                  : 'bg-white border-transparent hover:bg-slate-50 hover:border-slate-200'
              }`}
            >
              <div className="flex items-center justify-between">
                <div>
                  <h4 className="font-semibold text-slate-900">{patient.name}</h4>
                  <p className="text-xs text-slate-500">ID: {patient.id} • DOB: {patient.dob}</p>
                </div>
                {patient.historyAvailable && (
                  <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-indigo-100 text-indigo-800">
                    History
                  </span>
                )}
              </div>
            </div>
          ))}
          {filteredPatients.length === 0 && (
            <div className="text-center py-8 text-slate-400 text-sm">No patients found.</div>
          )}
        </div>
      </div>

      {/* Detail Column */}
      <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-slate-200 h-full overflow-hidden flex flex-col">
        {!selectedPatient ? (
          <div className="flex-1 flex flex-col items-center justify-center text-slate-400">
            <User className="w-16 h-16 mb-4 opacity-20" />
            <p>Select a patient to view details</p>
          </div>
        ) : (
          <>
            {/* Header */}
            <div className="p-6 border-b border-slate-100 flex justify-between items-start bg-slate-50">
              <div>
                <h2 className="text-2xl font-bold text-slate-900">{selectedPatient.name}</h2>
                <div className="flex items-center space-x-4 mt-2 text-sm text-slate-600">
                  <span className="flex items-center"><Calendar className="w-4 h-4 mr-1" /> DOB: {selectedPatient.dob}</span>
                  <span className="flex items-center"><Activity className="w-4 h-4 mr-1" /> Last Visit: {selectedPatient.lastVisit}</span>
                </div>
              </div>
              <div className={`px-3 py-1 rounded-full text-sm font-medium flex items-center ${
                selectedPatient.historyAvailable 
                  ? 'bg-emerald-100 text-emerald-800' 
                  : 'bg-slate-100 text-slate-600'
              }`}>
                {selectedPatient.historyAvailable ? (
                  <><CheckCircle className="w-4 h-4 mr-1.5" /> History Available</>
                ) : (
                  'No Prior History'
                )}
              </div>
            </div>

            {/* Content Area - Scrollable */}
            <div className="flex-1 overflow-y-auto p-6 space-y-8">

              {/* SOAP Report Section (Interactive) */}
              <div className="bg-white border border-slate-200 rounded-xl shadow-sm p-6 relative">
                 <div className="flex items-center justify-between mb-4">
                    <h3 className="text-lg font-bold text-slate-900 flex items-center">
                       <FileText className="w-5 h-5 mr-2 text-slate-500" />
                       Clinical Note (SOAP)
                    </h3>
                    <button 
                      onClick={handleSaveSoap}
                      className="text-sm font-medium text-kinetic-600 hover:text-kinetic-700 flex items-center"
                    >
                      {isSavingSoap ? 'Saving...' : lastSavedSoap ? 'Saved' : 'Save Draft'}
                      {!isSavingSoap && lastSavedSoap && <Check className="w-4 h-4 ml-1" />}
                    </button>
                 </div>

                 <div className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                       <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Subjective</label>
                          <textarea 
                             className="w-full p-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-kinetic-500 outline-none h-24 resize-none"
                             placeholder="Patient reports..."
                             value={soap.s}
                             onChange={e => setSoap({...soap, s: e.target.value})}
                          ></textarea>
                       </div>
                       <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Objective</label>
                          <textarea 
                             className="w-full p-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-kinetic-500 outline-none h-24 resize-none"
                             placeholder="ROM, Strength, etc..."
                             value={soap.o}
                             onChange={e => setSoap({...soap, o: e.target.value})}
                          ></textarea>
                       </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                       <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Assessment</label>
                          <textarea 
                             className="w-full p-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-kinetic-500 outline-none h-24 resize-none"
                             placeholder="Diagnosis/Impression..."
                             value={soap.a}
                             onChange={e => setSoap({...soap, a: e.target.value})}
                          ></textarea>
                       </div>
                       <div>
                          <label className="block text-xs font-bold text-slate-500 uppercase mb-1">Plan</label>
                          <textarea 
                             className="w-full p-3 border border-slate-300 rounded-lg text-sm focus:ring-2 focus:ring-kinetic-500 outline-none h-24 resize-none"
                             placeholder="Treatment plan..."
                             value={soap.p}
                             onChange={e => setSoap({...soap, p: e.target.value})}
                          ></textarea>
                       </div>
                    </div>
                 </div>
              </div>

              {/* External History Section */}
              <div className="border-t border-slate-200 pt-8">
                <h3 className="text-lg font-bold text-slate-900 mb-4 flex items-center">
                   <Activity className="w-5 h-5 mr-2 text-slate-500" />
                   Network History
                </h3>

                {!selectedPatient.historyAvailable ? (
                   <div className="p-8 bg-slate-50 rounded-xl border border-dashed border-slate-300 text-center text-slate-500">
                     No external history records found in Kinetic network.
                   </div>
                ) : isUnlocked ? (
                  /* Unlocked View */
                  patientHistory ? (
                    <div className="bg-slate-50 rounded-xl border border-slate-200 p-6 animate-fade-in">
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                        <div>
                          <label className="text-xs font-bold text-slate-400 uppercase mb-1 block">Condition</label>
                          <p className="text-lg font-semibold text-slate-900">{patientHistory.condition}</p>
                          <span className={`inline-block mt-2 px-2 py-0.5 rounded text-xs font-bold uppercase ${
                             patientHistory.status === 'Resolved' ? 'bg-emerald-100 text-emerald-700' : 'bg-amber-100 text-amber-700'
                           }`}>{patientHistory.status}</span>
                        </div>
                        <div>
                          <label className="text-xs font-bold text-slate-400 uppercase mb-1 block">Timeline</label>
                          <p className="text-sm text-slate-800">{patientHistory.timelineStart} — {patientHistory.timelineEnd || 'Present'}</p>
                          <label className="text-xs font-bold text-slate-400 uppercase mt-4 mb-1 block">Source</label>
                          <p className="text-xs text-slate-500 font-mono">Clinic ({patientHistory.sourceClinicHash.substring(0,8)})</p>
                        </div>
                      </div>

                      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                         <div>
                            <span className="text-xs font-semibold text-emerald-600 block mb-2">Effective</span>
                            <div className="flex flex-wrap gap-2">
                              {patientHistory.successfulTreatments.map(t => (
                                <span key={t} className="px-3 py-1 bg-white border border-emerald-200 text-emerald-700 rounded-md text-sm shadow-sm">{t}</span>
                              ))}
                            </div>
                         </div>
                         <div>
                            <span className="text-xs font-semibold text-rose-600 block mb-2">Ineffective</span>
                            <div className="flex flex-wrap gap-2">
                              {patientHistory.unsuccessfulTreatments.map(t => (
                                <span key={t} className="px-3 py-1 bg-white border border-rose-200 text-rose-700 rounded-md text-sm shadow-sm">{t}</span>
                              ))}
                            </div>
                         </div>
                      </div>

                      <div className="mb-6">
                        <span className="text-xs font-semibold text-rose-600 block mb-2">Contraindications</span>
                        <div className="flex flex-wrap gap-2">
                          {patientHistory.contraindications.map(c => (
                            <span key={c} className="flex items-center px-3 py-1 bg-white text-rose-700 border border-rose-200 rounded-md text-sm font-medium">
                              <AlertTriangle className="w-3 h-3 mr-1.5" /> {c}
                            </span>
                          ))}
                        </div>
                      </div>

                      {/* Documents */}
                      <div className="bg-white border border-slate-200 rounded-lg p-4 flex items-center justify-between mb-4">
                        <div className="flex items-center">
                          <FileText className="w-8 h-8 text-slate-400 mr-3" />
                          <div>
                            <p className="text-sm font-bold text-slate-900">SOAP Report</p>
                            <p className="text-xs text-slate-500">
                              {patientHistory.reportFile ? `Available: ${patientHistory.reportFile}` : 'No report attached'}
                            </p>
                          </div>
                        </div>
                        <div className="flex items-center space-x-2">
                          {patientHistory.reportFile ? (
                             <button 
                               onClick={handleDownloadReport}
                               className="flex items-center px-3 py-1.5 bg-kinetic-600 border border-transparent rounded text-sm font-medium text-white hover:bg-kinetic-700 shadow-sm"
                             >
                               <Download className="w-4 h-4 mr-2" /> Download PDF
                             </button>
                          ) : (
                             <button 
                               onClick={handleFileUpload}
                               disabled={isUploading}
                               className="flex items-center px-3 py-1.5 bg-white border border-slate-200 rounded text-sm font-medium text-slate-700 hover:bg-slate-50"
                             >
                               {isUploading ? 'Uploading...' : 'Upload SOAP'}
                               {!isUploading && <Upload className="w-4 h-4 ml-2 text-slate-400" />}
                             </button>
                          )}
                        </div>
                      </div>

                      <div className="flex justify-end">
                        <button 
                          onClick={handleCopyHistory}
                          className={`flex items-center text-sm font-medium px-4 py-2 rounded-lg transition-all ${
                            copied ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                          }`}
                        >
                           {copied ? <Check className="w-4 h-4 mr-2" /> : <Copy className="w-4 h-4 mr-2" />}
                           {copied ? 'Copied to Clipboard' : 'Copy History Text'}
                        </button>
                      </div>
                    </div>
                  ) : <div className="text-red-500">Error data</div>
                ) : (
                  /* Locked View */
                  <div className="bg-slate-900 rounded-xl p-8 text-center text-white relative overflow-hidden">
                     <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -mr-16 -mt-16 blur-3xl"></div>
                     <Lock className="w-12 h-12 mx-auto text-slate-400 mb-4" />
                     <h3 className="text-xl font-bold mb-2">History Available</h3>
                     <p className="text-slate-400 mb-6 max-w-sm mx-auto">
                       Unlock verified clinical outcomes, treatment responses, and contraindications.
                     </p>

                     <div className="flex items-center justify-center space-x-4 mb-6">
                        <div className="text-sm">
                           <span className="text-slate-400 mr-2">Cost:</span>
                           <span className="font-bold">1 Point</span>
                        </div>
                        <div className="w-px h-4 bg-slate-700"></div>
                        <div className="text-sm">
                           <span className="text-slate-400 mr-2">Balance:</span>
                           <span className={`font-bold ${credits > 0 ? 'text-emerald-400' : 'text-red-400'}`}>{credits}</span>
                        </div>
                     </div>

                     {isExpired ? (
                       <div className="inline-flex items-center px-4 py-2 bg-rose-500/20 text-rose-300 rounded-lg text-sm border border-rose-500/50">
                         <CalendarClock className="w-4 h-4 mr-2" />
                         Points Expired
                       </div>
                     ) : !isOptedIn ? (
                       <div className="inline-flex items-center px-4 py-2 bg-slate-800 text-slate-400 rounded-lg text-sm border border-slate-700">
                         Opt-In Required
                       </div>
                     ) : (
                       <button
                          onClick={handleUnlock}
                          disabled={credits <= 0}
                          className={`px-8 py-3 rounded-xl font-bold transition-all ${
                            credits > 0 
                              ? 'bg-kinetic-600 hover:bg-kinetic-500 shadow-lg shadow-kinetic-900/50' 
                              : 'bg-slate-700 text-slate-500 cursor-not-allowed'
                          }`}
                        >
                          {credits > 0 ? 'Unlock History' : 'Insufficient Points'}
                        </button>
                     )}
                  </div>
                )}
              </div>
            </div>
          </>
        )}
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Lock, Unlock, Calendar, Clock, CheckCircle, MoreHorizontal, X, Activity, AlertTriangle, CalendarClock } from 'lucide-react';
import { Patient, HistoryEntry, Appointment } from '../types';
import { MOCK_SCHEDULE } from '../constants';

interface DashboardProps {
  credits: number;
  unlockedPatients: string[];
  patients: Patient[];
  histories: HistoryEntry[];
  onNavigate: (tab: string) => void;
  onUnlock: (patientId: string) => void;
  isOptedIn: boolean;
  pointsExpiry: Date | null;
}

export const Dashboard: React.FC<DashboardProps> = ({ 
  credits, 
  unlockedPatients, 
  patients, 
  histories,
  onUnlock,
  isOptedIn,
  pointsExpiry
}) => {
  const [selectedPatientId, setSelectedPatientId] = useState<string | null>(null);

  const getPatient = (id: string) => patients.find(p => p.id === id);
  const getHistory = (id: string) => histories.find(h => h.patientId === id);

  const handleOpenHistory = (patientId: string) => {
    setSelectedPatientId(patientId);
  };

  const handleUnlockAndOpen = (patientId: string) => {
    onUnlock(patientId);
    // UI check: we assume parent handles validation. If not opted in or expired, parent won't unlock.
    // We only open modal if it WAS unlocked (sync or async)
    // For this simple demo, we can just attempt to open if we know it *should* work
    if (isOptedIn && credits > 0 && (!pointsExpiry || new Date() <= pointsExpiry)) {
      setSelectedPatientId(patientId);
    }
  };

  const closeModal = () => setSelectedPatientId(null);

  const selectedPatient = selectedPatientId ? getPatient(selectedPatientId) : null;
  const selectedHistory = selectedPatientId ? getHistory(selectedPatientId) : null;
  const isSelectedUnlocked = selectedPatientId ? unlockedPatients.includes(selectedPatientId) : false;
  const isExpired = pointsExpiry && new Date() > pointsExpiry;

  return (
    <div className="space-y-8">
      {/* Header Stats */}
      <div className="flex items-center justify-between">
        <div>
           <h2 className="text-2xl font-bold text-slate-900">Today's Schedule</h2>
           <p className="text-slate-500">{new Date().toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}</p>
        </div>
        <div className="flex space-x-4">
          <div className="bg-white px-4 py-2 rounded-lg border border-slate-200 shadow-sm flex items-center">
             <span className="text-xs font-bold text-slate-400 uppercase tracking-wide mr-2">Points</span>
             <span className="text-xl font-bold text-kinetic-600">{credits}</span>
             {isExpired && (
               <span className="ml-2 px-2 py-0.5 bg-rose-100 text-rose-700 text-xs rounded font-bold">Expired</span>
             )}
          </div>
        </div>
      </div>

      {/* Schedule List */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-4 bg-slate-50 border-b border-slate-200 grid grid-cols-12 gap-4 text-xs font-bold text-slate-500 uppercase tracking-wider">
          <div className="col-span-2">Time</div>
          <div className="col-span-4">Patient</div>
          <div className="col-span-3">Reason</div>
          <div className="col-span-3 text-right">Actions</div>
        </div>
        <div className="divide-y divide-slate-100">
          {MOCK_SCHEDULE.map((apt) => {
            const patient = getPatient(apt.patientId);
            const isUnlocked = unlockedPatients.includes(apt.patientId);
            const hasHistory = patient?.historyAvailable;

            return (
              <div key={apt.id} className="p-4 grid grid-cols-12 gap-4 items-center hover:bg-slate-50 transition-colors">
                <div className="col-span-2 flex items-center text-slate-700 font-medium">
                  <Clock className="w-4 h-4 mr-2 text-slate-400" />
                  {apt.time}
                </div>
                <div className="col-span-4">
                  <div className="font-semibold text-slate-900">{patient?.name || 'Unknown'}</div>
                  <div className="text-xs text-slate-500 flex items-center">
                    <span className={`inline-block w-2 h-2 rounded-full mr-2 ${
                      apt.status === 'Arrived' ? 'bg-emerald-500' :
                      apt.status === 'Completed' ? 'bg-slate-300' : 'bg-blue-500'
                    }`}></span>
                    {apt.status}
                  </div>
                </div>
                <div className="col-span-3 text-sm text-slate-600">
                  {apt.reason}
                </div>
                <div className="col-span-3 flex justify-end">
                  {!hasHistory ? (
                    <span className="text-xs text-slate-400 italic py-2">No history</span>
                  ) : isUnlocked ? (
                    <button 
                      onClick={() => handleOpenHistory(apt.patientId)}
                      className="flex items-center text-sm font-medium text-kinetic-600 bg-kinetic-50 px-3 py-1.5 rounded-lg hover:bg-kinetic-100 transition-colors"
                    >
                      <Unlock className="w-3 h-3 mr-2" />
                      View History
                    </button>
                  ) : (
                    <button 
                      onClick={() => handleUnlockAndOpen(apt.patientId)}
                      disabled={credits <= 0 || isExpired || !isOptedIn}
                      className={`flex items-center text-sm font-medium px-3 py-1.5 rounded-lg border transition-all ${
                        credits > 0 && !isExpired && isOptedIn
                          ? 'bg-white border-slate-200 text-slate-700 hover:border-kinetic-500 hover:text-kinetic-600 shadow-sm' 
                          : 'bg-slate-100 border-transparent text-slate-400 cursor-not-allowed'
                      }`}
                    >
                      {isExpired ? <CalendarClock className="w-3 h-3 mr-2" /> : <Lock className="w-3 h-3 mr-2" />}
                      {isExpired ? 'Expired' : !isOptedIn ? 'Locked' : 'Unlock (-1 Pt)'}
                    </button>
                  )}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* History Modal */}
      {selectedPatientId && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={closeModal}></div>
          <div className="bg-white rounded-2xl shadow-2xl w-full max-w-2xl max-h-[90vh] overflow-hidden flex flex-col relative animate-fade-in-up">

            {/* Modal Header */}
            <div className="p-6 border-b border-slate-100 flex justify-between items-center bg-slate-50">
              <div>
                 <h3 className="text-xl font-bold text-slate-900">{selectedPatient?.name}</h3>
                 <p className="text-sm text-slate-500">History Record</p>
              </div>
              <button onClick={closeModal} className="p-2 rounded-full hover:bg-slate-200 text-slate-500">
                <X className="w-5 h-5" />
              </button>
            </div>

            {/* Modal Content */}
            <div className="flex-1 overflow-y-auto p-6">
              {isSelectedUnlocked && selectedHistory ? (
                 <div className="space-y-6">
                    <div className="grid grid-cols-2 gap-4">
                      <div className="bg-slate-50 p-4 rounded-lg">
                        <label className="text-xs font-bold text-slate-400 uppercase">Condition</label>
