                Source: {sourceClinic}
              </div>
            )}
          </div>
        </CardBody>
      )}
    </Card>
  );
};

// ============================================================================
// ACTION CARD - For CTAs and Quick Actions
// ============================================================================
interface ActionCardProps {
  title: string;
  description: string;
  icon: React.ReactNode;
  iconColor?: string;
  buttonText: string;
  buttonColor?: string;
  badge?: string;
  onClick: () => void;
}

export const ActionCard: React.FC<ActionCardProps> = ({
