        {buttonText}
        <ChevronRight className="w-4 h-4 ml-2" />
      </button>
    </CardHeader>
  </Card>
);

// ============================================================================
// INFO CARD - For Notifications and Alerts
// ============================================================================
interface InfoCardProps {
  type: 'info' | 'success' | 'warning' | 'error';
  title: string;
  message: string;
  onDismiss?: () => void;
}

export const InfoCard: React.FC<InfoCardProps> = ({
  type,
