                   )}
                </div>
              )}
            </div>

          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Search, ArrowLeft, FileText, Check, Save, Activity, CheckCircle, Upload, Download, Copy, Calendar, User, Lock, CalendarClock, AlertTriangle } from 'lucide-react';
import { Patient, HistoryEntry } from '../types';
import { DEMO_PDF_BASE64 } from '../constants';
import { ClinicalSnapshotCard } from './ClinicalSnapshotCard';
import { PatientCard, HistoryEntryCard } from './ui/cards';

interface PatientSearchProps {
  patients: Patient[];
  histories: HistoryEntry[];
  unlockedPatients: string[];
  credits: number;
  onUnlock: (patientId: string) => void;
  onUploadReport: (patientId: string, fileName: string) => void;
  soapDrafts: Record<string, { s: string; o: string; a: string; p: string }>;
  onSaveSoap: (patientId: string, data: { s: string; o: string; a: string; p: string }) => void;
  isOptedIn: boolean;
  pointsExpiry: Date | null;
}

export const PatientSearch: React.FC<PatientSearchProps> = ({ 
  patients, 
  histories, 
  unlockedPatients, 
  credits, 
  onUnlock,
  onUploadReport,
  soapDrafts,
  onSaveSoap,
  isOptedIn,
  pointsExpiry
}) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedPatient, setSelectedPatient] = useState<Patient | null>(null);

  // Local state for UI feedback
  const [isUploading, setIsUploading] = useState(false);
  const [copied, setCopied] = useState(false);

  // SOAP Form State
  const [soap, setSoap] = useState({ s: '', o: '', a: '', p: '' });
  const [isSavingSoap, setIsSavingSoap] = useState(false);
  const [lastSavedSoap, setLastSavedSoap] = useState<Date | null>(null);

  // Reset states or load draft when patient changes
  useEffect(() => {
    setIsUploading(false);
    setCopied(false);
    if (selectedPatient) {
      const draft = soapDrafts[selectedPatient.id] || { s: '', o: '', a: '', p: '' };
      setSoap(draft);
    } else {
      setSoap({ s: '', o: '', a: '', p: '' });
    }
    setLastSavedSoap(null);
  }, [selectedPatient, soapDrafts]);

  const filteredPatients = patients.filter(p => 
    p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
    p.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const patientHistory = selectedPatient 
    ? histories.find(h => h.patientId === selectedPatient.id) 
    : null;

  const isUnlocked = selectedPatient ? unlockedPatients.includes(selectedPatient.id) : false;
  const isExpired = pointsExpiry && new Date() > pointsExpiry;

  const handleUnlock = () => {
    if (selectedPatient && credits > 0 && !isExpired && isOptedIn) {
      onUnlock(selectedPatient.id);
    }
  };

  const handleFileUpload = () => {
    if (!selectedPatient) return;
    setIsUploading(true);
    setTimeout(() => {
      onUploadReport(selectedPatient.id, "soap_report_final.pdf");
      setIsUploading(false);
    }, 1500);
  };

  const handleDownloadReport = () => {
    const byteCharacters = atob(DEMO_PDF_BASE64);
    const byteNumbers = new Array(byteCharacters.length);
    for (let i = 0; i < byteCharacters.length; i++) {
      byteNumbers[i] = byteCharacters.charCodeAt(i);
    }
    const byteArray = new Uint8Array(byteNumbers);
    const blob = new Blob([byteArray], { type: 'application/pdf' });

    const url = window.URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', patientHistory?.reportFile || 'soap_report.pdf');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    window.URL.revokeObjectURL(url);
  };

  const handleCopyHistory = () => {
    if (!patientHistory) return;
    const text = `Patient History: ${selectedPatient?.name}...`; // Simplified for brevity
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleSaveSoap = () => {
    if (!selectedPatient) return;
    setIsSavingSoap(true);
    onSaveSoap(selectedPatient.id, soap);
    setTimeout(() => {
      setIsSavingSoap(false);
      setLastSavedSoap(new Date());
    }, 500);
  };

  // SEARCH VIEW (Grid of Cards)
  if (!selectedPatient) {
    return (
      <div className="space-y-6">
        <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm">
          <h2 className="text-xl font-bold text-slate-900 mb-4">Patient Directory</h2>
          <div className="relative max-w-lg">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
            <input
              type="text"
              className="w-full pl-10 pr-4 py-3 border border-slate-300 rounded-lg text-base focus:ring-2 focus:ring-kinetic-500 focus:border-kinetic-500 outline-none"
              placeholder="Search by name or ID..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredPatients.map(patient => {
            const isPtUnlocked = unlockedPatients.includes(patient.id);
            return (
              <PatientCard
                key={patient.id}
                id={patient.id}
                name={patient.name}
                dob={patient.dob}
                lastVisit={patient.lastVisit}
                historyAvailable={patient.historyAvailable}
                snapshotAvailable={patient.historyAvailable} // Assuming mock matches
                isUnlocked={isPtUnlocked}
                onViewHistory={() => setSelectedPatient(patient)}
                onViewSnapshot={() => setSelectedPatient(patient)}
              />
            );
          })}
          {filteredPatients.length === 0 && (
             <div className="col-span-full text-center py-12 text-slate-400">
               No patients found matching "{searchTerm}"
             </div>
          )}
        </div>
      </div>
    );
  }

  // DETAIL VIEW
  return (
    <div className="h-full flex flex-col space-y-6">
      <button 
        onClick={() => setSelectedPatient(null)}
        className="self-start flex items-center text-slate-500 hover:text-slate-900 font-medium transition-colors"
      >
        <ArrowLeft className="w-4 h-4 mr-2" />
        Back to Directory
      </button>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        {/* Header */}
        <div className="p-6 border-b border-slate-100 flex justify-between items-start bg-slate-50">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">{selectedPatient.name}</h2>
            <div className="flex items-center space-x-4 mt-2 text-sm text-slate-600">
              <span className="flex items-center"><Calendar className="w-4 h-4 mr-1" /> DOB: {selectedPatient.dob}</span>
              <span className="flex items-center"><Activity className="w-4 h-4 mr-1" /> Last Visit: {selectedPatient.lastVisit}</span>
            </div>
          </div>
          <div className={`px-3 py-1 rounded-full text-sm font-medium flex items-center ${
            selectedPatient.historyAvailable 
              ? 'bg-emerald-100 text-emerald-800' 
              : 'bg-slate-100 text-slate-600'
          }`}>
            {selectedPatient.historyAvailable ? (
              <><CheckCircle className="w-4 h-4 mr-1.5" /> History Available</>
            ) : (
              'No Prior History'
            )}
          </div>
        </div>

        <div className="p-6 space-y-8">
           {/* SOAP Section */}
           <div className="bg-white border border-slate-200 rounded-xl shadow-sm p-6 relative">
             <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-bold text-slate-900 flex items-center">
                   <FileText className="w-5 h-5 mr-2 text-slate-500" />
                   Clinical Note (SOAP)
                </h3>
                <button 
                  onClick={handleSaveSoap}
                  className="text-sm font-medium text-kinetic-600 hover:text-kinetic-700 flex items-center"
                >
                  {isSavingSoap ? 'Saving...' : lastSavedSoap ? 'Saved' : 'Save Draft'}
                  {!isSavingSoap && lastSavedSoap && <Check className="w-4 h-4 ml-1" />}
                </button>
             </div>
             <div className="space-y-4">
                <div className="grid grid-cols-2 gap-4">
                   <textarea className="w-full p-3 border border-slate-300 rounded-lg text-sm h-24 resize-none outline-none focus:ring-2 focus:ring-kinetic-500" placeholder="Subjective..." value={soap.s} onChange={e => setSoap({...soap, s: e.target.value})} />
                   <textarea className="w-full p-3 border border-slate-300 rounded-lg text-sm h-24 resize-none outline-none focus:ring-2 focus:ring-kinetic-500" placeholder="Objective..." value={soap.o} onChange={e => setSoap({...soap, o: e.target.value})} />
                </div>
                <div className="grid grid-cols-2 gap-4">
                   <textarea className="w-full p-3 border border-slate-300 rounded-lg text-sm h-24 resize-none outline-none focus:ring-2 focus:ring-kinetic-500" placeholder="Assessment..." value={soap.a} onChange={e => setSoap({...soap, a: e.target.value})} />
                   <textarea className="w-full p-3 border border-slate-300 rounded-lg text-sm h-24 resize-none outline-none focus:ring-2 focus:ring-kinetic-500" placeholder="Plan..." value={soap.p} onChange={e => setSoap({...soap, p: e.target.value})} />
                </div>
             </div>
          </div>

          {/* Network History */}
          <div className="border-t border-slate-200 pt-8">
             <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-bold text-slate-900 flex items-center">
                   <Activity className="w-5 h-5 mr-2 text-slate-500" />
                   Network History
                </h3>
                {isUnlocked && (
                  <button onClick={handleCopyHistory} className="text-xs font-medium px-3 py-1.5 bg-slate-100 rounded-lg hover:bg-slate-200 transition-colors flex items-center">
                    {copied ? <Check className="w-3 h-3 mr-1.5"/> : <Copy className="w-3 h-3 mr-1.5"/>} Copy
                  </button>
                )}
             </div>

             {!selectedPatient.historyAvailable ? (
               <div className="p-8 bg-slate-50 border border-dashed border-slate-300 rounded-xl text-center text-slate-500">
                 No external history available.
               </div>
             ) : (
               <div className="space-y-6">
                 <ClinicalSnapshotCard
                    patientId={selectedPatient.id}
                    isUnlocked={isUnlocked}
                    credits={credits}
                    onUnlock={handleUnlock}
                    historyEntry={patientHistory}
                 />

                 {isUnlocked && patientHistory && (
                    <>
                      <HistoryEntryCard 
                        condition={patientHistory.condition}
                        timelineStart={patientHistory.timelineStart}
                        timelineEnd={patientHistory.timelineEnd}
                        status={patientHistory.status}
                        successfulTreatments={patientHistory.successfulTreatments.join(', ')}
                        unsuccessfulTreatments={patientHistory.unsuccessfulTreatments.join(', ')}
                        sourceClinic={patientHistory.sourceClinicHash}
                        isExpanded={true}
                        onToggle={() => {}} // Optional toggle if we wanted it collapsible
                      />

                      <div className="bg-slate-50 border border-slate-200 rounded-lg p-4 flex items-center justify-between">
                         <div className="flex items-center">
                            <FileText className="w-8 h-8 text-slate-400 mr-3" />
                            <div>
                               <p className="text-sm font-bold text-slate-900">Original SOAP Report</p>
                               <p className="text-xs text-slate-500">{patientHistory.reportFile || 'No file attached'}</p>
                            </div>
                         </div>
                         <div className="flex items-center space-x-2">
                           {patientHistory.reportFile ? (
                              <button onClick={handleDownloadReport} className="flex items-center px-3 py-1.5 bg-white border border-slate-200 rounded text-sm font-medium shadow-sm hover:bg-slate-50">
                                <Download className="w-4 h-4 mr-2" /> PDF
                              </button>
                           ) : (
                              <button onClick={handleFileUpload} disabled={isUploading} className="flex items-center px-3 py-1.5 bg-white border border-slate-200 rounded text-sm font-medium hover:bg-slate-50">
                                {isUploading ? 'Uploading...' : 'Upload'} <Upload className="w-4 h-4 ml-2" />
                              </button>
                           )}
                         </div>
                      </div>
                    </>
                 )}
               </div>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Check, Plus, ArrowRight, RefreshCcw, Loader2, Save, FileText, Info, X } from 'lucide-react';
import { Status } from '../types';
import { TREATMENTS_LIST, CONTRAINDICATIONS_LIST } from '../constants';
import { InfoCard } from './ui/cards';

interface ContributionFormProps {
  onSubmit: (data: any) => void;
  onReturn?: () => void;
}

const STORAGE_KEY = 'kinetic_contribution_draft';

export const ContributionForm: React.FC<ContributionFormProps> = ({ onSubmit, onReturn }) => {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [error, setError] = useState<string | null>(null);

  const initialFormState = {
    patientId: '',
    condition: '',
    status: Status.ONGOING,
    start: '',
    end: '',
    successful: [] as string[],
    unsuccessful: [] as string[],
    contraindications: [] as string[]
  };

  const [formData, setFormData] = useState(initialFormState);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load draft on mount
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        setFormData(JSON.parse(savedData));
        setLastSaved(new Date());
      } catch (e) {
        console.error("Failed to parse draft", e);
      }
    }
    setIsLoaded(true);
  }, []);

  // Auto-save draft (debounced)
  useEffect(() => {
    if (!isLoaded) return;
    if (step === 3) return; // Don't save when on success screen

    setIsSaving(true);
    const handler = setTimeout(() => {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
      setLastSaved(new Date());
      setIsSaving(false);
    }, 1000);

    return () => clearTimeout(handler);
  }, [formData, isLoaded, step]);

  const handleInputChange = (field: string, value: any) => {
    setError(null);
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const toggleSelection = (field: 'successful' | 'unsuccessful' | 'contraindications', value: string) => {
    setError(null);
    setFormData(prev => {
      const current = prev[field];
      if (current.includes(value)) {
        return { ...prev, [field]: current.filter(item => item !== value) };
      } else {
        return { ...prev, [field]: [...current, value] };
      }
    });
  };

  const validateStep1 = () => {
    if (!formData.patientId.trim()) return "Patient ID is required.";
    if (!formData.condition.trim()) return "Primary Condition is required.";
    if (!formData.start) return "Treatment Start Date is required.";
    return null;
  };

  const handleNextStep = () => {
    const validationError = validateStep1();
    if (validationError) {
      setError(validationError);
      return;
    }
    setError(null);
    setStep(2);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const validationError = validateStep1();
    if (validationError) {
      setStep(1);
      setError(validationError);
      return;
    }

    setIsSubmitting(true);
    setError(null);

    try {
      // Simulate API call
      await new Promise((resolve, reject) => {
        setTimeout(() => {
          const isError = Math.random() > 0.98; 
          if (isError) {
            reject(new Error("Network connection timed out. Please try again."));
          } else {
            resolve(true);
          }
        }, 1500);
      });

      // Submit to parent (this will trigger the parent's notification)
      onSubmit(formData);

      // Clear draft
      localStorage.removeItem(STORAGE_KEY);

      // Navigate to success screen (step 3)
      setStep(3);

    } catch (err: any) {
      setError(err.message || "An unexpected error occurred.");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleReset = () => {
    setFormData(initialFormState);
    localStorage.removeItem(STORAGE_KEY);
    setStep(1);
    setLastSaved(null);
    setError(null);
  };

  // SUCCESS SCREEN (Step 3)
  if (step === 3) {
    return (
      <div className="max-w-2xl mx-auto mt-12 text-center">
        <div className="bg-emerald-50 rounded-3xl p-12 border border-emerald-100 shadow-sm animate-fade-in">
          <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-6">
            <Check className="w-10 h-10 text-emerald-600" />
          </div>
          <h2 className="text-3xl font-bold text-slate-900 mb-2">Contribution Verified</h2>
          <p className="text-slate-600 mb-8 max-w-md mx-auto">
            Thank you for improving the network. Your data has been structured and anonymized.
          </p>

          <div className="inline-flex items-center space-x-2 bg-white px-6 py-3 rounded-xl border border-emerald-200 shadow-sm mb-8">
            <span className="text-sm font-medium text-slate-500">Reward Earned:</span>
            <span className="text-lg font-bold text-emerald-600">+1 Kinetic Point</span>
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button 
              onClick={handleReset}
              className="w-full sm:w-auto flex items-center justify-center px-6 py-3 bg-slate-900 text-white rounded-lg font-semibold hover:bg-slate-800 transition-all"
            >
              <Plus className="w-4 h-4 mr-2" />
              Contribute Another
            </button>
            {onReturn && (
              <button 
                onClick={onReturn}
                className="w-full sm:w-auto flex items-center justify-center px-6 py-3 bg-white text-slate-700 border border-slate-300 rounded-lg font-semibold hover:bg-slate-50 transition-all"
              >
                <FileText className="w-4 h-4 mr-2" />
                Return to Intake
              </button>
            )}
          </div>
        </div>
      </div>
    );
  }

  // FORM SCREENS (Step 1 & 2)
  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8 flex items-end justify-between">
        <div>
          <h2 className="text-2xl font-bold text-slate-900">Contribute Patient History</h2>
          <p className="text-slate-500 mt-2">
            Earn 1 Kinetic Point by sharing structured outcome data.
          </p>
        </div>

        <div className="flex items-center space-x-2">
           {isSaving ? (
              <div className="flex items-center text-xs font-medium text-slate-400 bg-slate-100 px-3 py-1 rounded-full">
                <Loader2 className="w-3 h-3 mr-1.5 animate-spin" />
                Saving...
              </div>
           ) : lastSaved ? (
              <div className="flex items-center text-xs font-medium text-slate-500 bg-slate-100 px-3 py-1 rounded-full">
                <Save className="w-3 h-3 mr-1.5 text-slate-400" />
                Draft saved
              </div>
           ) : null}
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="h-2 bg-slate-100 flex">
          <div className={`h-full bg-emerald-500 transition-all duration-500 ${step === 1 ? 'w-1/2' : 'w-full'}`}></div>
        </div>

        {error && (
          <div className="p-4">
             <InfoCard type="error" title="Validation Error" message={error} onDismiss={() => setError(null)} />
          </div>
        )}

        <div className="p-8 space-y-8">
          {step === 1 && (
            <div className="space-y-6">
              <InfoCard 
                type="info" 
                title="Strictly Structured Data Only" 
                message="To ensure privacy and utility, free-text notes are disabled." 
              />

              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Patient ID / Reference</label>
                  <input 
                    required
                    type="text" 
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                    placeholder="e.g. P-10293"
                    value={formData.patientId}
                    onChange={e => handleInputChange('patientId', e.target.value)}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Primary Condition</label>
                  <input 
                    required
                    type="text" 
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                    placeholder="e.g. Achilles Tendinopathy"
                    value={formData.condition}
                    onChange={e => handleInputChange('condition', e.target.value)}
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-3">Outcome Status</label>
                <div className="flex space-x-4">
                  {Object.values(Status).map((s) => (
                    <button
                      key={s}
                      type="button"
                      onClick={() => handleInputChange('status', s)}
                      className={`flex-1 py-3 px-4 rounded-lg border text-sm font-semibold transition-all ${
                        formData.status === s
                          ? 'bg-emerald-50 border-emerald-500 text-emerald-700 ring-1 ring-emerald-500'
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {s}
                    </button>
                  ))}
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Treatment Start</label>
                  <input 
                    type="date" 
                    required
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                    value={formData.start}
                    onChange={e => handleInputChange('start', e.target.value)}
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium text-slate-700 mb-1">Treatment End (Optional)</label>
                  <input 
                    type="date" 
                    className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                    value={formData.end}
                    onChange={e => handleInputChange('end', e.target.value)}
                  />
                </div>
              </div>
            </div>
          )}

          {step === 2 && (
            <div className="space-y-8">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2 flex items-center">
                  <Check className="w-4 h-4 text-emerald-500 mr-2" />
                  What Worked? (Successful Interventions)
                </label>
                <div className="flex flex-wrap gap-2">
                  {TREATMENTS_LIST.map(t => (
                    <button
                      key={t}
                      type="button"
                      onClick={() => toggleSelection('successful', t)}
                      className={`px-3 py-1.5 rounded-full text-sm font-medium border transition-colors ${
                        formData.successful.includes(t)
                          ? 'bg-emerald-100 border-emerald-500 text-emerald-800'
                          : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                      }`}
                    >
                      {t}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2 flex items-center">
                  <X className="w-4 h-4 text-rose-500 mr-2" />
                  What Didn't Work? (Unsuccessful Interventions)
                </label>
                <div className="flex flex-wrap gap-2">
                  {TREATMENTS_LIST.map(t => (
                    <button
                      key={t}
                      type="button"
                      onClick={() => toggleSelection('unsuccessful', t)}
                      className={`px-3 py-1.5 rounded-full text-sm font-medium border transition-colors ${
                        formData.unsuccessful.includes(t)
                          ? 'bg-rose-100 border-rose-500 text-rose-800'
                          : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                      }`}
                    >
                      {t}
                    </button>
                  ))}
                </div>
              </div>

              <div className="p-4 bg-amber-50 rounded-lg border border-amber-100">
                <label className="block text-sm font-bold text-amber-800 mb-2 flex items-center">
                  <Info className="w-4 h-4 mr-2" />
                  Safety & Contraindications
                </label>
                <p className="text-xs text-amber-700 mb-3">
                   Select any specific red flags or treatments that should be avoided.
                </p>
                <div className="flex flex-wrap gap-2">
                  {CONTRAINDICATIONS_LIST.map(c => (
                    <button
                      key={c}
                      type="button"
                      onClick={() => toggleSelection('contraindications', c)}
                      className={`px-3 py-1.5 rounded text-xs font-bold uppercase tracking-wide border transition-colors ${
                        formData.contraindications.includes(c)
                          ? 'bg-amber-600 border-amber-700 text-white shadow-sm'
                          : 'bg-white border-amber-200 text-amber-800 hover:bg-amber-100'
                      }`}
                    >
                      {c}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          )}
        </div>

        <div className="px-8 py-4 bg-slate-50 border-t border-slate-200 flex justify-between items-center">
          {step === 2 ? (
            <button
              type="button"
              onClick={() => setStep(1)}
              className="text-slate-600 font-medium hover:text-slate-900"
            >
              Back
            </button>
          ) : (
            <div></div>
          )}

          {step === 1 ? (
            <button
              type="button"
              onClick={handleNextStep}
              className="bg-slate-900 text-white px-6 py-2 rounded-lg font-semibold hover:bg-slate-800 transition-colors flex items-center"
            >
              Next Step <ArrowRight className="w-4 h-4 ml-2" />
            </button>
          ) : (
            <button
              type="button"
              onClick={handleSubmit}
              disabled={isSubmitting}
              className={`flex items-center space-x-2 px-6 py-2 rounded-lg font-semibold text-white transition-all ${
                isSubmitting 
                  ? 'bg-emerald-400 cursor-wait' 
                  : 'bg-emerald-600 hover:bg-emerald-700 shadow-lg'
              }`}
            >
              {isSubmitting ? (
                <>
                   <RefreshCcw className="w-5 h-5 animate-spin" />
                   <span>Verifying...</span>
                </>
              ) : (
                <>
                  <Plus className="w-5 h-5" />
                  <span>Submit & Earn Points</span>
                </>
              )}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { 
  TrendingUp, Users, Unlock, Award, Clock, CheckCircle, 
  Lock, AlertCircle, Plus, FileText, Eye, Info, ChevronRight,
  Activity, Database, Shield
} from 'lucide-react';

// ============================================================================
// BASE CARD COMPONENT - Reusable Foundation
// ============================================================================
interface BaseCardProps {
  children: React.ReactNode;
  className?: string;
  hover?: boolean;
  onClick?: () => void;
}

export const Card: React.FC<BaseCardProps> = ({ 
  children, 
  className = '', 
  hover = false,
  onClick 
}) => (
  <div 
    onClick={onClick}
    className={`bg-white rounded-xl border border-slate-200 ${
      hover ? 'hover:shadow-lg hover:border-slate-300 transition-all cursor-pointer' : 'shadow-sm'
    } ${className}`}
  >
    {children}
  </div>
);

export const CardHeader: React.FC<{ children: React.ReactNode; className?: string; onClick?: () => void }> = ({ 
  children, 
  className = '',
  onClick
}) => (
  <div className={`p-6 ${className}`} onClick={onClick}>
    {children}
  </div>
