import React, { useState, useEffect } from 'react';
import { Check, Info, Plus, X, ArrowRight, RefreshCcw, AlertCircle, Loader2, Save, FileText, ArrowLeft, Tag, Activity, Calendar, Upload, Sparkles } from 'lucide-react';
import { Status } from '../types';
import { TREATMENTS_LIST, CONTRAINDICATIONS_LIST } from '../constants';
import { InfoCard } from './ui/cards';

interface ContributionFormProps {
  onSubmit: (data: any) => void;
  onReturn?: () => void;
}

const STORAGE_KEY = 'kinetic_contribution_draft_v2';

const BODY_REGIONS = ['Cervical Spine', 'Thoracic Spine', 'Lumbar Spine', 'Shoulder', 'Elbow', 'Wrist/Hand', 'Hip', 'Knee', 'Ankle/Foot'];
const COMPLAINT_TYPES = ['Pain', 'Stiffness', 'Instability', 'Weakness', 'Post-Operative', 'Mobility Deficit'];
const REHAB_STAGES = ['Acute', 'Sub-Acute', 'Chronic', 'Return to Sport', 'Maintenance'];

export const ContributionForm: React.FC<ContributionFormProps> = ({ onSubmit, onReturn }) => {
  const [step, setStep] = useState(1);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [lastSaved, setLastSaved] = useState<Date | null>(null);
  const [error, setError] = useState<string | null>(null);

  const initialFormState = {
    // Step 1: Patient Info
    patientId: '',
    patientName: '',
    dob: '',
    start: '',
    end: '',

    // Step 2: Keywords & Structure
    bodyRegion: '',
    complaintType: '',
    rehabStage: '',
    status: Status.ONGOING,
    successful: [] as string[],
    unsuccessful: [] as string[],
    contraindications: [] as string[],

    // Step 3: Optional SOAP (Simplified)
    objectiveFindings: '',
    assessment: '',
    plan: ''
  };

  const [formData, setFormData] = useState(initialFormState);
  const [isLoaded, setIsLoaded] = useState(false);

  // Load draft on mount
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        setFormData(JSON.parse(savedData));
        setLastSaved(new Date());
      } catch (e) {
        console.error("Failed to parse draft", e);
      }
    }
    setIsLoaded(true);
  }, []);

  // Auto-save draft
  useEffect(() => {
    if (!isLoaded) return;
    if (step === 4) return; // Don't save on success screen

    setIsSaving(true);
    const handler = setTimeout(() => {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
      setLastSaved(new Date());
      setIsSaving(false);
    }, 1000);

    return () => clearTimeout(handler);
  }, [formData, isLoaded, step]);

  const handleInputChange = (field: string, value: any) => {
    setError(null);
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const toggleArraySelection = (field: 'successful' | 'unsuccessful' | 'contraindications', value: string) => {
    setError(null);
    setFormData(prev => {
      const current = prev[field];
      if (current.includes(value)) {
        return { ...prev, [field]: current.filter(item => item !== value) };
      } else {
        return { ...prev, [field]: [...current, value] };
      }
    });
  };

  // Validation Logic
  const validateStep1 = () => {
    if (!formData.patientId.trim()) return "Patient ID is required.";
    if (!formData.patientName.trim()) return "Patient Name is required.";
    if (!formData.dob) return "Date of Birth is required.";
    return null;
  };

  const validateStep2 = () => {
    if (!formData.bodyRegion) return "Please select a Body Region.";
    if (!formData.complaintType) return "Please select a Complaint Type.";
    if (!formData.rehabStage) return "Please select a Rehab Stage.";
    return null;
  };

  const handleNextStep = () => {
    let validationError = null;
    if (step === 1) validationError = validateStep1();
    if (step === 2) validationError = validateStep2();

    if (validationError) {
      setError(validationError);
      window.scrollTo(0, 0);
      return;
    }

    setError(null);
    setStep(prev => prev + 1);
    window.scrollTo(0, 0);
  };

  const handleBack = () => {
    setStep(prev => prev - 1);
    setError(null);
    window.scrollTo(0, 0);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    // Final check
    const err1 = validateStep1();
    const err2 = validateStep2();

    if (err1 || err2) {
      setError(err1 || err2);
      setStep(err1 ? 1 : 2);
      return;
    }

    setIsSubmitting(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 1000));

      // Construct the composite condition string for the legacy type definition
      const compositeCondition = `${formData.bodyRegion} - ${formData.complaintType}`;

      onSubmit({
        ...formData,
        condition: compositeCondition
      });

      localStorage.removeItem(STORAGE_KEY);
      setStep(4);
    } catch (err: any) {
      setError(err.message || "An error occurred");
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleReset = () => {
    setFormData(initialFormState);
    localStorage.removeItem(STORAGE_KEY);
    setStep(1);
    setError(null);
  };

  // Success Screen
  if (step === 4) {
    return (
      <div className="max-w-2xl mx-auto mt-12 text-center px-4">
        <div className="bg-emerald-50 rounded-3xl p-8 md:p-12 border border-emerald-100 shadow-sm animate-fade-in-up">
          <div className="w-20 h-20 bg-emerald-100 rounded-full flex items-center justify-center mx-auto mb-6">
            <Check className="w-10 h-10 text-emerald-600" />
          </div>
          <h2 className="text-2xl md:text-3xl font-bold text-slate-900 mb-2">Contribution Verified</h2>
          <p className="text-slate-600 mb-8 max-w-md mx-auto">
            Your structured clinical data has been successfully added to the Kinetic Network.
          </p>

          <div className="inline-flex items-center space-x-2 bg-white px-6 py-3 rounded-xl border border-emerald-200 shadow-sm mb-8">
            <span className="text-sm font-medium text-slate-500">Reward Earned:</span>
            <span className="text-lg font-bold text-emerald-600">+1 Credit</span>
          </div>

          <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
            <button 
              onClick={handleReset}
              className="w-full sm:w-auto flex items-center justify-center px-6 py-3 bg-slate-900 text-white rounded-lg font-semibold hover:bg-slate-800 transition-all"
            >
              <Plus className="w-4 h-4 mr-2" />
              Contribute Another
            </button>
            {onReturn && (
              <button 
                onClick={onReturn}
                className="w-full sm:w-auto flex items-center justify-center px-6 py-3 bg-white text-slate-700 border border-slate-300 rounded-lg font-semibold hover:bg-slate-50 transition-all"
              >
                <FileText className="w-4 h-4 mr-2" />
                Return to Intake
              </button>
            )}
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="max-w-4xl mx-auto px-4 pb-24">
      {/* Header & Nav */}
      <div className="mb-6">
        <button
          onClick={onReturn}
          className="flex items-center px-4 py-2 bg-slate-100 hover:bg-slate-200 text-slate-700 rounded-lg font-medium transition-colors border border-slate-300 mb-6"
        >
          <ArrowLeft className="w-4 h-4 mr-2" />
          Back to Dashboard
        </button>

        <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
          <div>
            <h2 className="text-2xl font-bold text-slate-900">Contribute History</h2>
            <p className="text-slate-500 mt-1">Earn 1 Credit by sharing structured clinical outcomes.</p>
          </div>

          <div className="flex items-center space-x-3 text-sm">
             {isSaving && <span className="text-slate-400 flex items-center"><Loader2 className="w-3 h-3 mr-1 animate-spin"/> Saving draft...</span>}
             {!isSaving && lastSaved && <span className="text-slate-400 flex items-center"><Check className="w-3 h-3 mr-1"/> Saved</span>}
          </div>
        </div>
      </div>

      {/* Progress Stepper */}
      <div className="mb-8 bg-white rounded-xl border border-slate-200 p-4 shadow-sm flex items-center justify-between">
        <div className={`flex items-center ${step >= 1 ? 'text-emerald-600' : 'text-slate-400'}`}>
          <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold mr-3 ${step >= 1 ? 'bg-emerald-100' : 'bg-slate-100'}`}>1</div>
          <span className="hidden sm:inline font-medium">Patient Info</span>
        </div>
        <div className="h-0.5 w-12 bg-slate-200"></div>
        <div className={`flex items-center ${step >= 2 ? 'text-emerald-600' : 'text-slate-400'}`}>
          <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold mr-3 ${step >= 2 ? 'bg-emerald-100' : 'bg-slate-100'}`}>2</div>
          <span className="hidden sm:inline font-medium">Key Data</span>
        </div>
        <div className="h-0.5 w-12 bg-slate-200"></div>
        <div className={`flex items-center ${step >= 3 ? 'text-blue-600' : 'text-slate-400'}`}>
          <div className={`w-8 h-8 rounded-full flex items-center justify-center font-bold mr-3 ${step >= 3 ? 'bg-blue-100' : 'bg-slate-100'}`}>3</div>
          <span className="hidden sm:inline font-medium">Notes (Optional)</span>
        </div>
      </div>

      {error && (
        <InfoCard 
          type="error" 
          title="Validation Error" 
          message={error} 
          onDismiss={() => setError(null)} 
        />
      )}

      {/* Form Steps */}
      <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden">

        {/* Step 1: Demographics */}
        {step === 1 && (
          <div className="p-6 md:p-8 space-y-6">
            <div className="flex items-center mb-4">
              <div className="bg-emerald-100 p-2 rounded-lg mr-3">
                <FileText className="w-6 h-6 text-emerald-600" />
              </div>
              <div>
                <h3 className="text-lg font-bold text-slate-900">Patient Identification</h3>
                <p className="text-sm text-slate-500">Basic demographic information required for record linkage.</p>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Patient ID (Medicare No.) <span className="text-red-500">*</span></label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                  placeholder="e.g. 1234 56789 1"
                  value={formData.patientId}
                  onChange={e => handleInputChange('patientId', e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Full Name <span className="text-red-500">*</span></label>
                <input 
                  type="text" 
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                  placeholder="e.g. Jane Doe"
                  value={formData.patientName}
                  onChange={e => handleInputChange('patientName', e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Date of Birth <span className="text-red-500">*</span></label>
                <input 
                  type="date" 
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                  value={formData.dob}
                  onChange={e => handleInputChange('dob', e.target.value)}
                />
              </div>
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-1">Treatment Start Date</label>
                <input 
                  type="date" 
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-emerald-500 outline-none"
                  value={formData.start}
                  onChange={e => handleInputChange('start', e.target.value)}
                />
              </div>
            </div>
          </div>
        )}

        {/* Step 2: Keywords */}
        {step === 2 && (
          <div className="p-6 md:p-8 space-y-8">
            <div className="flex items-center mb-4">
              <div className="bg-emerald-100 p-2 rounded-lg mr-3">
                <Tag className="w-6 h-6 text-emerald-600" />
              </div>
              <div>
                <h3 className="text-lg font-bold text-slate-900">Clinical Classification</h3>
                <p className="text-sm text-slate-500">Select structured keywords to categorize the case.</p>
              </div>
            </div>

            {/* Keyword Selection Grid */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-3">Body Region <span className="text-red-500">*</span></label>
                <div className="space-y-2">
                  {BODY_REGIONS.map(region => (
                    <button
                      key={region}
                      type="button"
                      onClick={() => handleInputChange('bodyRegion', region)}
                      className={`w-full text-left px-4 py-2 rounded-lg text-sm border transition-all ${
                        formData.bodyRegion === region 
                          ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-medium shadow-sm' 
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {region}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-3">Complaint Type <span className="text-red-500">*</span></label>
                <div className="space-y-2">
                  {COMPLAINT_TYPES.map(type => (
                    <button
                      key={type}
                      type="button"
                      onClick={() => handleInputChange('complaintType', type)}
                      className={`w-full text-left px-4 py-2 rounded-lg text-sm border transition-all ${
                        formData.complaintType === type 
                          ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-medium shadow-sm' 
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {type}
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-3">Rehab Stage <span className="text-red-500">*</span></label>
                <div className="space-y-2">
                  {REHAB_STAGES.map(stage => (
                    <button
                      key={stage}
                      type="button"
                      onClick={() => handleInputChange('rehabStage', stage)}
                      className={`w-full text-left px-4 py-2 rounded-lg text-sm border transition-all ${
                        formData.rehabStage === stage 
                          ? 'bg-emerald-50 border-emerald-500 text-emerald-700 font-medium shadow-sm' 
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {stage}
                    </button>
                  ))}
                </div>
              </div>
            </div>

            {/* Treatments & Outcome */}
            <div className="pt-6 border-t border-slate-200">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div>
                   <label className="block text-sm font-semibold text-slate-700 mb-3 flex items-center">
                     <Check className="w-4 h-4 text-emerald-500 mr-2" />
                     Effective Interventions
                   </label>
                   <div className="flex flex-wrap gap-2">
                     {TREATMENTS_LIST.map(t => (
                       <button
                         key={t}
                         type="button"
                         onClick={() => toggleArraySelection('successful', t)}
                         className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${
                           formData.successful.includes(t)
                             ? 'bg-emerald-100 border-emerald-500 text-emerald-800'
                             : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                         }`}
                       >
                         {t}
                       </button>
                     ))}
                   </div>
                </div>

                <div>
                   <label className="block text-sm font-semibold text-slate-700 mb-3 flex items-center">
                     <X className="w-4 h-4 text-rose-500 mr-2" />
                     Ineffective Interventions
                   </label>
                   <div className="flex flex-wrap gap-2">
                     {TREATMENTS_LIST.map(t => (
                       <button
                         key={t}
                         type="button"
                         onClick={() => toggleArraySelection('unsuccessful', t)}
                         className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${
                           formData.unsuccessful.includes(t)
                             ? 'bg-rose-100 border-rose-500 text-rose-800'
                             : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
                         }`}
                       >
                         {t}
                       </button>
                     ))}
                   </div>
                </div>
              </div>
            </div>

            <div className="pt-6 border-t border-slate-200">
               <label className="block text-sm font-semibold text-slate-700 mb-3">Current Status</label>
               <div className="flex space-x-4">
                  {Object.values(Status).map((s) => (
                    <button
                      key={s}
                      type="button"
                      onClick={() => handleInputChange('status', s)}
                      className={`flex-1 py-2 px-4 rounded-lg border text-sm font-semibold transition-all ${
                        formData.status === s
                          ? 'bg-blue-50 border-blue-500 text-blue-700 ring-1 ring-blue-500'
                          : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50'
                      }`}
                    >
                      {s}
                    </button>
                  ))}
               </div>
            </div>
          </div>
        )}

        {/* Step 3: Optional Notes */}
        {step === 3 && (
          <div className="p-6 md:p-8 space-y-6">
            <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-2">
              <div className="flex items-center">
                <div className="bg-blue-100 p-2 rounded-lg mr-3">
                  <FileText className="w-6 h-6 text-blue-600" />
                </div>
                <div>
                  <h3 className="text-lg font-bold text-slate-900">SOAP Notes <span className="text-slate-400 font-normal ml-2">(Optional)</span></h3>
                  <p className="text-sm text-slate-500">Provide detailed findings if available.</p>
                </div>
              </div>

              <div className="flex space-x-2">
                 {/* Demo-only Upload Button */}
                 <button className="flex items-center px-3 py-2 bg-white border border-slate-300 rounded-lg text-sm font-medium text-slate-700 hover:bg-slate-50 transition-colors">
                    <Upload className="w-4 h-4 mr-2" />
                    Upload SOAP Report
                 </button>

                 {/* Demo-only AI Placeholder */}
                 <div className="group relative flex items-center px-3 py-2 bg-indigo-50 border border-indigo-100 rounded-lg text-sm font-medium text-indigo-400 cursor-not-allowed">
                    <Sparkles className="w-4 h-4 mr-2" />
                    AI Transcribe
                    <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 bg-slate-800 text-white text-xs rounded py-1 px-2 text-center opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none">
                       AI-assisted transcription (coming soon)
                    </div>
                 </div>
              </div>
            </div>

            <InfoCard 
              type="info" 
              title="Optional Step" 
              message="You can submit the form now if you don't have detailed notes to add." 
            />

            <div className="space-y-6">
              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Objective Findings</label>
                <textarea
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm min-h-[120px]"
                  placeholder="ROM, strength, special tests, functional assessments..."
                  value={formData.objectiveFindings}
                  onChange={e => handleInputChange('objectiveFindings', e.target.value)}
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Assessment / Analysis</label>
                <textarea
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm min-h-[100px]"
                  placeholder="Clinical impression, diagnosis, prognosis..."
                  value={formData.assessment}
                  onChange={e => handleInputChange('assessment', e.target.value)}
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-slate-700 mb-2">Plan of Care</label>
                <textarea
                  className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm min-h-[100px]"
                  placeholder="Treatment frequency, interventions, home program..."
                  value={formData.plan}
                  onChange={e => handleInputChange('plan', e.target.value)}
                />
              </div>
            </div>
          </div>
        )}

        {/* Action Bar */}
        <div className="bg-slate-50 px-6 py-4 border-t border-slate-200 flex justify-between items-center sticky bottom-0 z-10">
          {step > 1 ? (
            <button
              type="button"
              onClick={handleBack}
              className="text-slate-600 font-medium hover:text-slate-900 px-4 py-2"
            >
              Back
            </button>
          ) : (
            <div></div> // Spacer
          )}

          {step < 3 ? (
            <button
              type="button"
              onClick={handleNextStep}
              className="bg-slate-900 text-white px-6 py-2.5 rounded-lg font-semibold hover:bg-slate-800 transition-colors flex items-center shadow-lg shadow-slate-200"
            >
              Next Step <ArrowRight className="w-4 h-4 ml-2" />
            </button>
          ) : (
            <button
              type="button"
              onClick={handleSubmit}
              disabled={isSubmitting}
              className={`flex items-center space-x-2 px-8 py-2.5 rounded-lg font-semibold text-white transition-all shadow-lg ${
                isSubmitting 
                  ? 'bg-emerald-400 cursor-wait' 
                  : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200'
              }`}
            >
              {isSubmitting ? (
                <>
                   <Loader2 className="w-5 h-5 animate-spin" />
                   <span>Verifying...</span>
                </>
              ) : (
                <>
                  <Check className="w-5 h-5" />
                  <span>Submit Contribution</span>
                </>
              )}
            </button>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { PatientSearch } from './components/PatientSearch';
import { ContributionForm } from './components/ContributionForm';
import { Referral } from './components/Referral';
import { MOCK_PATIENTS, MOCK_HISTORY } from './constants';
import { Patient, HistoryEntry, Status } from './types';
import { CheckCircle, Shield, Users } from 'lucide-react';

// Simple Alert Component for notifications
const Notification = ({ message, onClose }: { message: string; onClose: () => void }) => (
  <div className="fixed bottom-6 right-6 bg-slate-900 text-white px-6 py-4 rounded-xl shadow-2xl flex items-center animate-bounce-in z-50">
    <CheckCircle className="w-6 h-6 text-emerald-400 mr-3" />
    <div>
      <h4 className="font-bold text-sm">Success</h4>
      <p className="text-sm text-slate-300">{message}</p>
    </div>
    <button onClick={onClose} className="ml-6 text-slate-400 hover:text-white">✕</button>
  </div>
);

const App: React.FC = () => {
  // App State
  const [activeTab, setActiveTab] = useState('dashboard');
  const [credits, setCredits] = useState(0); // Start with 0
  const [unlockedPatients, setUnlockedPatients] = useState<string[]>([]);
  const [contributionCount, setContributionCount] = useState(12);
  const [localHistory, setLocalHistory] = useState<HistoryEntry[]>(MOCK_HISTORY);
  const [localPatients, setLocalPatients] = useState<Patient[]>(MOCK_PATIENTS);
  const [notification, setNotification] = useState<string | null>(null);

  // Track if initial credits were awarded (only once ever)
  const [hasReceivedInitialCredits, setHasReceivedInitialCredits] = useState(false);
  const [isOptedIn, setIsOptedIn] = useState(false); // Default to false - user must opt in

  // Load initial credits flag and opt-in status from storage on mount
  useEffect(() => {
    const hasReceived = localStorage.getItem('kinetic_initial_credits_awarded');
    const optInStatus = localStorage.getItem('kinetic_opted_in');
    const savedCredits = localStorage.getItem('kinetic_credits');

    if (hasReceived === 'true') {
      setHasReceivedInitialCredits(true);
    }

    // Set opt-in status
    if (optInStatus === 'true') {
      setIsOptedIn(true);
      // If opted in and has received credits before, restore them
      if (savedCredits && hasReceived === 'true') {
        setCredits(parseInt(savedCredits, 10));
      }
    } else {
      // FIX: First-time users should opt in and get 5 credits
      if (!hasReceived && !optInStatus) {
        // This is a brand new user - they need to opt in
        setIsOptedIn(false);
        setCredits(0);
      }
    }
  }, []);

  // Save credits to localStorage whenever they change
  useEffect(() => {
    if (credits > 0 || hasReceivedInitialCredits) {
      localStorage.setItem('kinetic_credits', credits.toString());
    }
  }, [credits, hasReceivedInitialCredits]);

  // Clear notification when changing tabs to avoid stale messages
  useEffect(() => {
    setNotification(null);
  }, [activeTab]);

  // Actions
  const handleUnlockPatient = (patientId: string) => {
    if (credits > 0) {
      setCredits(prev => prev - 1);
      setUnlockedPatients(prev => [...prev, patientId]);
      setNotification(`Unlocked history. Balance: ${credits - 1}`);
      setTimeout(() => setNotification(null), 3000);
    }
  };

  // Auto-unlock contributed patient history
  const handleContribution = (data: any) => {
    setCredits(prev => prev + 1);
    setContributionCount(prev => prev + 1);

    // Optimistically add to local data so we can see it
    const newHistory: HistoryEntry = {
      id: `H-${Math.random().toString(36).substr(2, 9)}`,
      patientId: data.patientId,
      condition: data.condition,
      timelineStart: data.start,
      timelineEnd: data.end,
      status: data.status,
      successfulTreatments: data.successful,
      unsuccessfulTreatments: data.unsuccessful,
      contraindications: data.contraindications,
      createdAt: new Date().toISOString(),
      sourceClinicHash: 'RIVERSDALE_PHYSIO'
    };

    setLocalHistory(prev => [...prev, newHistory]);

    // FIX: Auto-unlock the contributed patient's history
    if (!unlockedPatients.includes(data.patientId)) {
      setUnlockedPatients(prev => [...prev, data.patientId]);
    }

    // Check if patient exists, if not add them
    const existingPatientIndex = localPatients.findIndex(p => p.id === data.patientId);

    if (existingPatientIndex >= 0) {
      // Update existing patient
      const updatedPatients = [...localPatients];
      updatedPatients[existingPatientIndex] = {
        ...updatedPatients[existingPatientIndex],
        name: data.patientName || updatedPatients[existingPatientIndex].name,
        dob: data.dob || updatedPatients[existingPatientIndex].dob,
        historyAvailable: true
      };
      setLocalPatients(updatedPatients);
    } else {
      // Add new patient
      const newPatient: Patient = {
        id: data.patientId,
        name: data.patientName || `Patient ${data.patientId}`,
        dob: data.dob || 'Unknown',
        lastVisit: new Date().toISOString().split('T')[0],
        historyAvailable: true
      };
      setLocalPatients(prev => [...prev, newPatient]);
    }

    setNotification('Contribution verified. +1 Credit earned. History auto-unlocked.');
    setTimeout(() => {
      setNotification(null);
    }, 3000);
  };

  // FIX: Network opt-in handler - 5 trial credits only once
  const handleOptIn = () => {
    setIsOptedIn(true);
    localStorage.setItem('kinetic_opted_in', 'true');

    // FIX: Always award 5 credits on first-ever opt-in
    if (!hasReceivedInitialCredits) {
      setCredits(5); // Set to 5 instead of adding
      setHasReceivedInitialCredits(true);
      localStorage.setItem('kinetic_initial_credits_awarded', 'true');
      localStorage.setItem('kinetic_credits', '5');
      setNotification('Welcome! +5 trial credits awarded (one-time bonus).');
    } else {
      // Restore previous credits if they had any
      const savedCredits = localStorage.getItem('kinetic_credits');
      if (savedCredits) {
        setCredits(parseInt(savedCredits, 10));
      }
      setNotification('Opted back in to network. Your credits have been restored.');
    }
    setTimeout(() => setNotification(null), 3000);
  };

  // Network opt-out handler - removes all credits
  const handleOptOut = () => {
    setIsOptedIn(false);
    setCredits(0); // Remove all credits when opting out
    localStorage.setItem('kinetic_opted_in', 'false');
    localStorage.setItem('kinetic_credits', '0');
    setNotification('Opted out of network. All credits removed. Your data will not be shared.');
    setTimeout(() => setNotification(null), 3000);
  };

  return (
    <Layout activeTab={activeTab} onTabChange={setActiveTab} credits={credits}>
      {activeTab === 'dashboard' && (
        <Dashboard 
          credits={credits} 
          contributionCount={contributionCount} 
          unlockedCount={unlockedPatients.length}
          onNavigate={setActiveTab}
          isOptedIn={isOptedIn}
          onOptIn={handleOptIn}
          onOptOut={handleOptOut}
        />
      )}

      {activeTab === 'intake' && (
        <PatientSearch 
          patients={localPatients}
          histories={localHistory}
          unlockedPatients={unlockedPatients}
          credits={credits}
          onUnlock={handleUnlockPatient}
        />
      )}

      {activeTab === 'contribute' && (
        <ContributionForm 
          onSubmit={handleContribution} 
          onReturn={() => setActiveTab('intake')}
        />
      )}

      {activeTab === 'community' && (
        <div className="max-w-2xl mx-auto text-center pt-16">
          <div className="bg-indigo-50 w-24 h-24 rounded-full flex items-center justify-center mx-auto mb-6">
            <Users className="w-12 h-12 text-indigo-600" />
          </div>
          <h2 className="text-3xl font-bold text-slate-900 mb-4">Community Features Coming Soon</h2>
          <p className="text-slate-500 mb-8 max-w-lg mx-auto">
            Connect with other clinicians, discuss cases, and see how your contributions are helping others.
          </p>
          <div className="bg-white p-6 rounded-xl border border-slate-200 shadow-sm max-w-md mx-auto">
            <p className="text-sm font-medium text-slate-700 italic">
              "1,200 clinicians viewed this contribution and found it useful"
            </p>
            <p className="text-xs text-slate-400 mt-2">— Example of future community feedback</p>
          </div>
        </div>
      )}

      {activeTab === 'referrals' && (
        <Referral />
      )}

      {activeTab === 'settings' && (
        <div className="max-w-2xl mx-auto bg-white p-6 md:p-8 rounded-xl shadow-sm border border-slate-200">
           <h2 className="text-2xl font-bold mb-6">Settings</h2>
           <div className="space-y-6">
              {/* Network Opt-in/Opt-out Toggle */}
              <div className="flex items-center justify-between pb-6 border-b border-slate-100">
                <div>
                  <h3 className="font-semibold text-slate-900">Network Opt-in</h3>
                  <p className="text-sm text-slate-500">Allow other clinics to request your data (anonymized)</p>
                  {!isOptedIn && !hasReceivedInitialCredits && (
                    <p className="text-xs text-emerald-600 mt-1 font-semibold">✨ Get 5 free trial credits when you opt in!</p>
                  )}
                  {!isOptedIn && hasReceivedInitialCredits && (
                    <p className="text-xs text-amber-600 mt-1">⚠️ Opting out removed your credits</p>
                  )}
                </div>
                <button
                  onClick={isOptedIn ? handleOptOut : handleOptIn}
                  className={`relative inline-block w-12 h-6 transition duration-200 ease-in-out rounded-full ${
                    isOptedIn ? 'bg-emerald-500' : 'bg-slate-200'
                  }`}
                >
                   <span className={`absolute left-1 top-1 bg-white w-4 h-4 rounded-full shadow-md transition-transform ${
                     isOptedIn ? 'transform translate-x-6' : ''
                   }`}></span>
                </button>
              </div>

              <div className="flex items-center justify-between pb-6 border-b border-slate-100">
                <div>
                  <h3 className="font-semibold text-slate-900">Credit Auto-Refill</h3>
                  <p className="text-sm text-slate-500">Purchase credits if contribution isn't possible</p>
                </div>
                 <div className="relative inline-block w-12 h-6 transition duration-200 ease-in-out rounded-full bg-slate-200">
                   <span className="absolute left-1 top-1 bg-white w-4 h-4 rounded-full shadow-md"></span>
                </div>
              </div>

              {/* Data Security & Privacy Section */}
              <div className="pt-6 border-t border-slate-200">
                <h3 className="text-lg font-semibold text-slate-900 mb-4 flex items-center">
                  <Shield className="w-5 h-5 mr-2 text-blue-600" />
                  Data Security & Privacy
                </h3>

                <div className="space-y-4">
                  <div className="flex flex-col sm:flex-row sm:items-center justify-between pb-4 border-b border-slate-100 gap-2">
                    <div>
                      <h4 className="font-semibold text-slate-900">Data Encryption</h4>
                      <p className="text-sm text-slate-500">All patient data encrypted at rest and in transit</p>
                    </div>
                    <div className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-xs font-semibold self-start sm:self-auto">
                      ENABLED
                    </div>
                  </div>

                  <div className="flex flex-col sm:flex-row sm:items-center justify-between pb-4 border-b border-slate-100 gap-2">
                    <div>
                      <h4 className="font-semibold text-slate-900">Anonymization</h4>
                      <p className="text-sm text-slate-500">Patient identifiers are hashed before network sharing</p>
                    </div>
                    <div className="px-3 py-1 bg-emerald-100 text-emerald-700 rounded-full text-xs font-semibold self-start sm:self-auto">
                      ACTIVE
                    </div>
                  </div>

                  <div className="flex flex-col sm:flex-row sm:items-center justify-between pb-4 border-b border-slate-100 gap-2">
                    <div>
                      <h4 className="font-semibold text-slate-900">Audit Logging</h4>
                      <p className="text-sm text-slate-500">Track all data access and contributions</p>
                    </div>
                    <button className="text-sm text-blue-600 hover:text-blue-700 font-medium self-start sm:self-auto">
                      View Logs
                    </button>
                  </div>

                  <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-2">
                    <div>
                      <h4 className="font-semibold text-slate-900">Data Retention</h4>
                      <p className="text-sm text-slate-500">Contributed data retained for 24 months</p>
                    </div>
                    <span className="text-sm text-slate-600 font-medium self-start sm:self-auto">24 months</span>
                  </div>
                </div>
              </div>
           </div>

           <div className="mt-8 p-4 bg-slate-50 rounded-lg text-xs text-slate-500 font-mono">
             Clinic ID: KIN-ORG-882192<br/>
             Version: v0.4.3 (Beta)
           </div>
        </div>
      )}

      {notification && (
        <Notification message={notification} onClose={() => setNotification(null)} />
      )}
    </Layout>
  );
};

